INSERT INTO jobs VALUES(13,9,'Digital marketing executive',unistr('Summary: A Digital Marketing Executive is responsible for implementing and managing a company''s digital marketing campaigns to drive online traffic, brand awareness, and conversions. \u000aKey Duties:\u000aDevelop and execute digital marketing campaigns across various platforms (SEO, SEM, social media, email, etc.).\u000aManage and oversee the company''s social media presence, including content creation and community management.\u000aTrack, analyze, and report on website traffic, campaign performance, and KPIs using analytics tools.\u000aCollaborate with internal teams to align marketing efforts with business goals.\u000aOptimize digital content and campaigns for maximum engagement and ROI.\u000aStay up-to-date on the latest digital marketing trends and best practices.\u000aAssist in managing marketing budgets and allocating spend effectively.\u000aEnsure brand consistency across all digital channels. '),NULL,'open','2025-11-08 08:34:13','2025-11-08 08:35:09','Digital marketing');
INSERT INTO jobs VALUES(14,9,'Aws fresher',unistr('Required Skills & Qualifications\u000aExperience:\u000a\u000a0-6 months of experience with cloud computing, preferably with AWS.\u000aBasic understanding of cloud concepts and AWS services.\u000aTechnical Skills:\u000a\u000aFamiliarity with AWS services like EC2, S3, RDS and IAM is a plus.\u000aBasic knowledge of networking, Linux, and scripting languages (e.g., Python, Bash).\u000aEagerness to learn and adapt to new technologies and tools.\u000aSoft Skills:\u000a\u000aStrong analytical and problem-solving abilities.\u000aGood communication and teamwork skills.\u000aAbility to follow instructions and work independently when required.\u000aDetail-oriented with strong organizational skills.'),NULL,'open','2025-11-08 09:31:32','2025-11-08 09:31:32','cloud ');
INSERT INTO jobs VALUES(15,9,'software developer',unistr('Technical skills: Proficiency in HTML, CSS, and JavaScript is fundamental. Knowledge of modern JavaScript frameworks and libraries like React, Angular, or Vue.js is often required. \u000aDesign eye: A keen eye for detail, a strong sense of aesthetics, and the ability to create intuitive user experiences are important. \u000aProblem-solving: Strong analytical and problem-solving skills to troubleshoot and fix issues effectively. \u000aCommunication: Excellent verbal and written communication skills to collaborate with cross-functional teams and clients. \u000aUnderstanding of web standards: Knowledge of principles like responsive design, cross-browser compatibility, and SEO best practices. '),NULL,'open','2025-11-08 09:33:25','2025-11-08 09:33:25','Information and tech');
INSERT INTO jobs VALUES(16,9,'Founder''s office',unistr('Job Responsibilities \u000a\u000aThe Founder''s Office role acts as the strategic right-hand to the Founder/CEO, significantly expanding their bandwidth across critical areas. You''ll move seamlessly between high-level strategy and hands-on execution.\u000aStrategic Planning & Projects: Own the end-to-end execution of high-priority, cross-functional projects, which may include launching new service lines, exploring strategic partnerships, or defining quarterly OKRs (Objectives and Key Results).\u000aOperational Excellence: Diagnose organizational bottlenecks and implement scalable processes and systems to improve efficiency across teams (e.g., Sales, Client Success, AI Product Development).\u000aData Analysis & Decision Support: Conduct deep research and synthesize complex data into clear, actionable insights and memos for the Founder/CEO to support key business decisions.\u000aInternal & External Communications: Serve as a communication bridge, ensuring clear and timely information flow between the Founder, leadership, and external stakeholders (partners, potential investors).\u000aTalent & Culture: Assist in defining the hiring pipeline for key roles and help reinforce the company''s data-driven, entrepreneurial culture.\u000a\u000a\u000aWhat we are looking for:\u000a\u000aWe need an experienced operator who thrives in a high-velocity, ambiguous environment and possesses an exceptional blend of analytical rigor and communication mastery.\u000aExperience: 3+ years of experience in a high-growth startup, top-tier management consulting, investment banking, or a similar Chief of Staff/Founder''s Office role.\u000aExceptional Communication: World-class written and verbal communication skills with the ability to articulate complex strategies clearly to both internal technical teams and external non-technical clients/partners.\u000aAnalytical Acumen: Proven ability to structure and solve complex, undefined problems using data and logic. Proficiency in advanced Excel/Sheets, data visualization, and financial modeling is highly valued.\u000aHigh Agency & Ownership: A self-starter with a proactive, "get-it-done" mentality. You see problems as challenges to own and solve, not tasks to delegate upwards.\u000aDigital Marketing/AI Interest: A strong passion for the Digital Marketing and AI space, with a desire to learn the commercial applications of cutting-edge technology.\u000a\u000a\u000aWhy Join Viral Bug\u000a\u000aThis isn''t just a job; it''s an accelerator for your career.\u000aDirect Impact: Work side-by-side with the Founder, gaining a 360-degree view of how an AI-native business is scaled from the ground up.\u000aUnparalleled Learning: Gain exposure across every function - strategy, finance, operations, product development - making this the ultimate training ground for your entrepreneurial aspirations.\u000aBe at the Forefront of AI: Lead the charge in applying Artificial Intelligence to real-world marketing challenges, positioning you at the intersection of technology and business growth.\u000a\u000aShould pocess excellent communication skills in english.'),NULL,'open','2025-11-13 12:04:07','2025-11-13 12:04:07','Ceo Cabin');
INSERT INTO candidates VALUES(818,9,NULL,'Sehman Kumar','sehmankumar@gmail.com','90',NULL,NULL,'Sehman Kumar is a strategic finance and operations professional with 2+ years of cross-functional experience, demonstrating strong analytical acumen, exceptional communication, and a proactive approach to problem-solving. He has a proven track record in data-driven decision support, operational efficiency improvements, and leading strategic initiatives, particularly in finance, logistics, and marketing. While he possesses strong digital marketing skills and experience in fast-paced environments, his experience is slightly below the 3-year requirement, and explicit interest in AI and experience in talent & culture initiatives are not clearly demonstrated.','pending','row_2','2025-11-20 11:53:50','2025-11-25 11:00:55','971555867803',NULL,NULL,unistr('Sehman Kumar\u000a: sehmankumar@gmail.com | Age: 24 | Mobile : +971 55 586 7803\u000aCareer Summary\u000aStrategic finance and operations professional with 2+ years of cross-functional experience in the GCC and India. Proven ability to\u000asupport executive decision-making through data-driven insights, streamline cross-departmental operations, drive cost efficiencies, and\u000alead strategic initiatives across finance, logistics, and marketing in fast-paced, growth-focused environments.\u000aACADEMICS\u000aQualification Institute Board / University % /CGPA Year\u000aBMS (Bachelor’s in\u000aManagement Studies-\u000aspecialisation in\u000amarketing)\u000aShaheed Sukhdev College of Business\u000aStudies, Delhi \u000aUniversity Of Delhi 7.9 GPA 2022\u000aXII St. Marks Sr. Sec. School, Delhi AISSCE (Commerce) 91.25% 2019\u000aX \u000aRyan International School, Delhi \u000aAISSCE 9/10 2017\u000aWORK EXPERIENCE\u000aSumo Sushi & Bento, Dubai, UAE Finance Executive Feb 2024 - Present\u000aRoles and\u000aResponsibilities\u000a Prepare and analyze monthly purchase reports (AED 450K) and sales reports (AED 2M+),\u000adelivering actionable insights to support operational and strategic decision-making.\u000a Monitor and report on monthly company expenses, performing detailed variance analysis to\u000ahighlight discrepancies, improve cost efficiency, and ensure alignment with budget forecasts.\u000a Conduct comprehensive budget variance analysis across departments, identifying cost control\u000aopportunities and contributing to improved financial discipline.\u000a Track and evaluate key financial KPIs, providing performance insights and supporting\u000acontinuous improvement within the finance function.\u000a Led successful supplier negotiations and cost-benefit analyses, resulting in a 15% reduction in\u000achicken supply costs and a 12% decrease in transportation expenses.\u000a Played a pivotal role in the launch of ''Asian Chix'', a new fried chicken concept, by conducting\u000ain-depth market research, pricing strategy development, and financial feasibility studies.\u000a Analyze and track the performance of promotional campaigns, leveraging financial data to\u000aenhance return on investment and optimize future promotions.\u000a Oversee financial coordination with third-party delivery platforms (Noon, Talabat, Careem etc),\u000aensuring accurate reconciliations, timely fund releases, and reduced revenue deductions.\u000a Deliver data-driven strategic recommendations to senior management, influencing key decisions\u000aon pricing, supplier partnerships, marketing strategies, and branch expansion.\u000aLuxury Vacations and Holidays,\u000aPunjabi Bagh, New Delhi \u000aOperations Executive - Finance July 2023 – Jan 2024\u000aRoles and\u000aResponsibilities\u000a Coordinated between sales, marketing, and accounts teams to manage 100+ monthly bookings\u000aacross Dubai and Bali.\u000a Prepared payment schedules and projected cash outflows worth ₹25–30 lakhs per month, and\u000anegotiated credit terms with hotels to maximize the company’s working capital.\u000a Handled foreign remittances to Dubai and Bali worth ₹50 lakhs per month.\u000a Negotiated with suppliers, achieving up to 15% cost savings on hotels and sightseeing activities.\u000a Maintained strong client relations, ensuring 95% timely payment collections.\u000a Designed cost-benefit B2B packages, driving a 20% increase in monthly sales.\u000a\u000aACHEIVEMENTS\u000aDelhi University (Joint\u000aassessment test) \u000a All India Rank 28\u000aIndian Institute of\u000aManagement, Rohtak\u000a(IIM)\u000a Successfully cleared Integrated Program in Management Aptitude Test (IPMAT).\u000aINTERNSHIPS\u000aThe Holiday Adviser, Gurugram, New Delhi Marketing Intern 2021 ( 3 Months )\u000aRoles and\u000aResponsibilities\u000a Analysed marketing campaigns performance metrics, interpreting data and making data driven\u000aimprovements.\u000a Conducted market research to identify new target audience.\u000a Assisting the sales and marketing head in formulating various marketing strategies.\u000a Collaborated with the sales team to create promotional materials and sales collateral that\u000asupported lead generation efforts.\u000aElecon Cargos Pvt. Ltd., Gurugram, New Delhi Logistics Intern 2019 ( 3 Months )\u000aRoles and\u000aResponsibilities\u000a Analysed the principle of supply chain, including procurement, planning and distribution process.\u000a Assisted in coordinating shipments, tracking deliveries, and ensuring timely and accurate order\u000afulfilment worth 50 lakhs.\u000a Acquainted with custom laws and regulations, including tariff classification, import and export\u000aprocess, documentation requirements and custom clearance.\u000aROLES AND RESPONSIBILITY\u000aMember, Alumni\u000aOutreach Cell, Delhi\u000aUniversity\u000a Liaised between Alumni and college.\u000a Organized and invited various alumnus for workshops, seminars and networking sessions.\u000a Maintain and updated the college database.\u000aEvent Management,\u000aDelhi University\u000a Actively organized and promoted the annual cultural fest of Delhi University.\u000a Interacted with various students and faculty members and responded to inquiries regarding the\u000aevent.\u000a Provided marketing insights and promotional strategies to the marketing team.\u000aHead boy, School\u000a Provided strong and inspirational leadership to the student body, setting a high standard of\u000aconduct, behaviour, and academic achievement.\u000aSKILLS\u000a MS Excel, MS Office, Power Point\u000a ERP Software\u000a Business Acumen\u000a Financial Accounting\u000a Event Management and Administration Skill\u000a Project Management\u000a Strategic Management\u000a Marketing Management\u000aEXTRA CURRICULARS\u000a Digital Marketing Course by Google.\u000a Volunteered in HelpAge India programme\u000a Vedic Maths\u000a Content Marketing Course by HubSpot Academy\u000a Tally ERP by CSD Institute\u000aRESTS\u000aRESTS'),NULL);
INSERT INTO candidates VALUES(819,9,NULL,'NEVIS AMMAL RAJ','nevislasts4ever@gmail.com','86',NULL,NULL,'Nevis Ammal Raj Kuddru has 5 years of experience in product management, corporate relations, client partnership, and strategy, demonstrating strong capabilities in strategic growth initiatives, financial modeling, and acting as a strategic partner to founding teams.','pending','row_3','2025-11-20 11:53:50','2025-11-25 11:00:55','#ERROR!',NULL,NULL,unistr('NEVIS AMMAL RAJ\u000aKUDDRU\u000aCorporate Relations\u000aAbout Me\u000aProfessional Experience\u000aHaving 5 years of experience as a working professional in\u000athe Department Product Management, Corporate\u000aRelations, Client Partnership and Strategy\u000aHard Skill\u000aFinancial modeling and reporting\u000aEntrepreneurship Business Alliances\u000aStrategic Partnerships Contract\u000aNegotiation\u000aBusiness valuation\u000aTraining & Development People\u000aManagement Sales\u000aSoft Skill\u000aObservation\u000aDecision making\u000aCommunication\u000aMulti-tasking\u000aEducation Background\u000aSATHYABAMA UNIVERSITY\u000aBE AERONAUTICAL\u000aMy Contact\u000anevislasts4ever@gmail.com\u000aHyderabad, India\u000a+91 9035702503\u000aLearnWolf Pvt Ltd. | Head of Corporate Relations & Strategy\u000aLearning vertos EduTech Pvt Ltd. | Head of Corporate\u000aRelations & Strategy Analyst\u000aMarch 2023 – August 2024\u000aKey responsibilities:\u000aDrove strategic growth initiatives by identifying new market\u000aopportunities in the sustainable biotech and green innovation sectors,\u000adesigning and executing go-to-market (GTM) strategies for new\u000aproduct lines.\u000aCollaborated cross-functionally with Product, Marketing, and Sales\u000ateams to accelerate market entry and customer acquisition.\u000aBuilt financial and operational models, pitch decks, and strategic\u000anarratives to support investor discussions, fundraising, and\u000apartnerships.\u000aConducted competitive and market intelligence to guide leadership\u000adecisions, ensuring our positioning remained sharp in a rapidly\u000aevolving sustainability landscape.\u000aActed as a strategic partner to the founding team — anticipating\u000abusiness needs, driving team alignment, and ensuring timely\u000aexecution of key projects.\u000aKey responsibilities:\u000aLooked at financial performance and identified trends\u000aDevelop a growth strategy focused both on financial gain and\u000acustomer satisfaction.\u000aPrepare sales contracts ensuring adherence to law-established\u000arules and guidelines\u000aKeep records of sales, revenue, invoices\u000aJanuary 2022 - January 2023\u000aLanguages\u000aEnglish\u000aHindi\u000aTelugu\u000aTamil\u000aCreative Multimedia | Corporate Relations & Placement\u000aOfficer December 2024 - March 2025\u000aKey responsibilities:\u000aBuilding strong industry partnerships to maximize student\u000aplacements.\u000aAttracting premium companies, securing competitive\u000apackages, and aiming for 100% quality placements.\u000aCore focus includes arranging studio visits, internships,\u000aplacement coordination, and student grooming sessions.\u000aGreenworksbio Product Private Limited | Client Relation\u000aManager April 2025 - Present\u000aKey responsibilities:\u000aSpearheaded GTM execution for EdTech and digital learning solutions,\u000atranslating market research into actionable growth strategies.\u000aDefined product vision and strategy for EdTech solutions aligning with\u000acompany goals and evolving market needs.\u000aPartnered with cross-functional teams to design scalable product\u000aadoption models and optimize user acquisition funnels.\u000aDeveloped analytical frameworks and dashboards to measure growth\u000ametrics, product engagement, and campaign effectiveness.\u000aCreated investor-ready presentations and business narratives to support\u000afunding and partnership initiatives.\u000aSupported leadership in competitive benchmarking, opportunity\u000aanalysis, and operational scaling, contributing directly to business\u000aexpansion and strategic clarity.'),NULL);
INSERT INTO candidates VALUES(820,9,NULL,'SAPAVATU BHAGAVATHI','bhagavathi.sapavatu@gmail.com','96',NULL,NULL,'An accomplished professional with over 3 years of experience in Founder''s, MD''s, and CEO''s offices, demonstrating strong capabilities in strategic planning, project management, data analysis, and stakeholder communications. Proven track record in operational excellence, implementing OKRs, and a keen interest in Digital Marketing and AI.','pending','row_4','2025-11-20 11:53:50','2025-11-25 11:00:55','-8247434093',NULL,NULL,unistr('SAPAVATU BHAGAVATHI\u000abhagavathi.sapavatu@gmail.com\u000a+91-8247434184\u000aEDUCATION\u000aMBA \u000aIndian Institute of Management Bangalore – IIM Bangalore (’17-‘19) General Management\u000aB. TECH \u000aJawaharlal Nehru Technological University – JNTU Hyderabad (‘11-‘15) E.C.E\u000aWORK EXPERIENCE (75 MONTHS)\u000aNov’24 – Present Greenko Group \u000aStrategy Planning Group, MD’s Office\u000aBusiness Strategy /\u000aM&A\u000a• Led organization restructuring of Greenko Asset Management, mapping 20+ critical processes across Solar, Wind & Hydro; identified\u000amanpower optimization opportunities with projected 15–20% improvement, directly enabling MD’s transformation agenda\u000a• Advised MD & leadership on ₹400 Cr+ proposed Compressed Biogas M&A; conducted market diligence & recommended against acquisition\u000a• Delivered Market intelligence for AM Green’s proposed 1MTPA Aluminum Smelter & Refinery; assessed demand-supply dynamics &\u000acompetitive positioning, shaping board-level strategic decisions\u000a• Partnered with HR to design a Hi-Po (High Potential) Internal leadership development program; Benchmarked global Industry best practices.\u000aDigital Enablement\u000a• Enabled CXO decision-making by centralizing SAP MM, PM & FICO data into 20+ executive-ready SQL reports; reduced manual reporting\u000aby 30% and coordinated a 10+ member cross-functional team to deliver insights for CXO reviews\u000a• Spearheaded corporate website revamp enhancing investor accessibility & aligning digital presence with MD’s strategic comm. priorities\u000aJun’23 – Aug’24 Param Renewable Energy Strategy & PMO, Founder’s Office\u000aProfitability\u000aInitiatives\u000a• Led EBITDA improvement initiatives FY’24, impact of INR 5.4 Cr+ cost savings on 115 Cr portfolio through process automation &\u000aoptimization, resource allocation, and vendor renegotiation; Continuously tracked & reported on deliverables across 4+ functions\u000a• Spearheaded FY’25 Profitability initiatives analysis, identified 6+ projects based on 3-year historical data; P&L Analysis, conducted\u000afeasibility study, projected potential annualized savings of ~ INR 8 Cr on portfolio of INR 200 Cr\u000aMarket Expansion\u000a• Lead, US market expansion, developed a comprehensive GTM strategy, conducted in-depth competitor analysis, 10+ competitors, Gap/\u000aopportunity analysis, digital marketing strategy proposal & delivered insights; Developed investor-ready pitch decks\u000aExecutive\u000aGovernance\u000a• Implemented Institutionalized OKR framework across 6+ functions; partnered with CXOs on bi-monthly check-ins, reducing project\u000aoverruns by 50% and achieving 100% adoption within 3 months\u000a• Owned CEO communication cadence - Weekly executive updates, Monthly business reviews, and Investor-ready pitch decks; covered\u000a100+ KPIs across 5+ functions into actionable insights for CEO decision-making\u000aApr’21 – May’23 Vedanta Resources - HZL PMO, CEO’s Office\u000aProgram Management\u000a• Conceptualized and executed CEO’s strategic program, collaborated across 5+ functions, 6+ Business Units, supervised 10+ workshops,\u000aboosted EBITDA / Revenue by 9% and reduced cost of production resulting in savings of INR 20+ Cr\u000a• Oversaw HZL CEO’s Management Committee meetings, coordinated with CXOs to anticipate and proactively manage issues that\u000ahampers business continuity, created a mobile application and dashboard to continuously track key actionable\u000aBusiness Strategy\u000a• Built a 5-year Strategy Roadmap with CEO, performed domestic and global industry analysis, market research, competitor\u000abenchmarking and financial statement analysis, thereby delivering key actionable insights on potential business opportunities\u000a• Developed sourcing strategy through Market intelligence for key commodities, achieved savings of ~ INR 12.5 Cr on a spend base INR\u000a150 Cr through alternate vendor development and complimentary product procurement\u000aBusiness Analytics \u000a• Ideated, Executed and Solutioned LIVE business cases through structural data analysis, designed SOP for safety stock level of key raw\u000amaterials, achieved cost reduction of ~ INR 6 Cr\u000a• Conceptualized solution for power purchase optimization, performed historical data & Root cause analysis, Cost reduction ~ INR 5 Cr\u000aMay’19 - Mar’21 Program Manager, Finance\u000aEnterprise Analytics\u000aApps & BI\u000a• Designed and managed e2e development and adoption of mobile friendly Analytics Application empowered by AI /ML - Power BI tool,\u000acustomized Insights on critical KPIs to senior management integrated with O365; Spearheaded a team of 10+ data engineers\u000a• End to end conceptualization and deployment of In-house Digital Analytics Application, powered by BI tool Qlik sense, for personalized\u000ainsights on Operations, Finance, Marketing, Inventory Management & HR to drive key decisions across Value chain, 40+ interactive dashboards\u000a• Led a team of 8+ Qlik BI engineers, homogenized reporting methods across 6+ Business verticals, Automated 50+ reports, ensuring timely\u000areporting of critical reports, unlocked manual intervention time of 7200+ hours annually\u000a• Hosted 15 Live Demo sessions involving 250+ participants, strategized and implemented change management initiatives for adoption drive,\u000a‘Employee Adoption of Smart Dashboards’ to imbibe data driven decision making culture in the organization\u000aApr’18 – Jun’18 Vedanta Resources - HZL \u000aSummer Intern\u000aSupply Chain\u000aManagement\u000aDeveloped roadmap for Vendor Managed Inventory (VMI) system, identified high frequency items for Inventory Optimization to be incorporated\u000ain VMI, with a spend base of INR 100 Cr, realized gross working capital impact of ~ INR 20 Cr\u000aTools \u000aBI Tools: MS Power BI, Qlik Sense, Project Management Tools: MS Projects, Trello, JIRA\u000aSkills \u000aStakeholder Management, Executive Communication, OKRs, Leadership Alignment, Business Strategy, Market Intelligence, Business\u000aDevelopment, M&A, Expansion Strategy, Business Transformation, Program/Project Management, Process Optimization, Agile, ERP/ SAP\u000aACHIEVEMENTS\u000a• Data Con Awards''22 by The Economic Times in ‘Automated Data Management'', Spearheaded development of Enterprise Analytics Application ''HZL NorthStar''\u000a• Orchestrated Inhouse Data Analytics Application, received ‘Best Data Solution of year’ in Manufacturing category at Data World Summit and Awards, 2022\u000a• Awarded PPO, top 4/15+ secured a Pre-Placement-Offer (PPO) in Vedanta’s Flag ship program, VLDP (Vedanta Leadership & Development Program), 2019\u000a• National Merit Scholarship, Central Sector Scheme, 1/6k+/6.9L+ students, Ministry of HRD Human Resource Department, Government of India, 2010 -2011\u000a• Extended an offer to join Accenture Service Private Ltd, 1/65/1k+ students, Associate Software Engineer during Campus Placements drive, G.N.I.T.S 2015\u000aBeyond Work \u000aBuilt & scaled Digital community of 240k+ followers in 18 months on IG, creating high engagement content in Entertainment and Lifestyle\u000aAwarded Best Digital Influencer 2024 -Creators & Influencers Awards, supported by Govt. of Telangana, through public voting 2Mn+ votes'),NULL);
INSERT INTO candidates VALUES(821,9,NULL,'Priyanshu Srivastava','psrivastava252@gmail.com','90',NULL,NULL,'Strategic operator with 7+ years of experience in fintech and consulting, adept at driving CXO-level initiatives, GTM design, and scaling businesses. Possesses strong analytical and communication skills, with experience in founder-led execution.','pending','row_5','2025-11-20 11:53:50','2025-11-25 11:00:55','#ERROR!',NULL,NULL,unistr('Priyanshu Srivastava\u000a📧 psrivastava252@gmail.com | 📞 +91 9794228214 | \u000aLinkedIn\u000aStrategy & Product Analyst | CXO Office\u000aStrategic operator with 7+ years of experience driving CXO-level initiatives across fintech and\u000aconsulting. Currently enabling founder-led execution at Tide as a Strategy & Product Analyst.\u000aSkilled in GTM design, KPI governance, and scaling 0→1 business initiatives. Proven ability to\u000atranslate board-level priorities into actionable outcomes, align cross-functional teams, and drive\u000arevenue growth.\u000aCore Competencies\u000a● Business Strategy & Operations\u000a● Founder’s Office Execution\u000a● OKR & KPI Frameworks\u000a● GTM & Monetization Strategy\u000a● Board & CXO Reporting\u000a● Cross-functional Program Management\u000a● Data-driven Decision Making\u000a● Tools: SQL, Tableau, Looker, Google Analytics, Figma, MS Office\u000aProfessional Experience\u000aTide | Fintech Platform\u000aStrategy & Product Analyst\u000aMay 2022 – Present\u000a● Partnered with founders and CXOs to drive GTM strategy, scaling the merchant\u000aacquiring business from 0-$10M ARR.\u000a● Built CXO-level KPI tracking frameworks adopted company-wide, enabling data-driven\u000adecision-making and visibility across business lines.\u000a● Managed cross-functional governance across Product, Ops, and Compliance to achieve\u000afounder-driven strategic milestones.\u000a● Delivered board-ready performance reviews and operational insights influencing key\u000abusiness decisions.\u000a● Partnered with leadership to assess unit P&L and optimize pricing / cost structures.\u000aKantar | Strategy Division\u000aSenior Analyst\u000aJun 2021 – May 2022\u000a● Led strategy and analytics for credit card penetration projects, improving customer\u000aretention by 8%.\u000a\u000a● Designed and owned CXO dashboards providing actionable insights for leadership\u000adecision-making.\u000a● Coordinated cross-functional teams to align analytics with GTM and retention strategies.\u000aThe Outfit Basket | Founder\u000aEntrepreneurship & Business Strategy\u000a● Founded and operated an online apparel venture, overseeing product sourcing, vendor\u000apartnerships, and digital marketing strategy.\u000a● Built partnerships with local manufacturers and executed D2C go-to-market initiatives,\u000againing hands-on experience in full-stack business operations.\u000aUseready Technology\u000aSenior Analyst\u000aJul 2019 – May 2021\u000a● Built and managed global KPI dashboards enabling operational efficiency tracking\u000aacross product lines.\u000a● Developed roadmap for product optimization, resulting in a 4% ARPU uplift and\u000aimproved client engagement.\u000a● Partnered with business heads to institutionalize performance tracking processes.\u000aTimex Group\u000aTrainee, Planning & Procurement\u000aJun 2018 – Jun 2019\u000a● Supported demand forecasting and supply planning functions, optimizing procurement\u000atimelines.\u000aEducation\u000aB.Tech, Harcourt Butler Technical University\u000a2014 – 2018'),NULL);
INSERT INTO candidates VALUES(822,9,NULL,'Kavita H.','mahemkavita17@gmail.com','86',NULL,NULL,'Head of Projects and Strategic Program Leader with 6+ years of experience driving high-impact, cross-functional projects and executing Founder’s Office initiatives, known for solving undefined challenges and delivering on time-sensitive goals.','pending','row_6','2025-11-20 11:53:50','2025-11-25 11:00:55','#ERROR!',NULL,NULL,unistr('Kavita H.\u000aGurugram, Haryana, India | +91 9911574347 | mahemkavita17@gmail.com | LinkedIn\u000aCAREER PROFILE\u000aHead of Projects and Strategic Program Leader with 6+ years of experience driving high-impact, cross-functional projects across analytics,\u000aoperations, healthcare research, media, and organizational strategy in India and U.S. markets. Known for executing Founder’s Office initiatives,\u000asolving undefined challenges, and delivering on time-sensitive, business-critical goals. Skilled in stakeholder management, vendor optimization, and\u000ascalable systems design.\u000aPROFESSIONAL EXPERIENCE\u000aAIG Business Solutions Pvt. Ltd. – Gurugram, India\u000aAIG is a Delhi-based healthcare startup that owns and operates as the back office for hospitals and physician groups in the USA and India, including Heart,\u000aVascular & Leg Center (California, USA), Truxtun Foot & Ankle Specialists (California, USA), Amerix Cancer Hospital (India), etc.\u000aHead of Projects Jul 2022 – Present\u000a• Worked directly with the Founders as a key member of the Founder’s Office.\u000a• Interviewed and facilitated placement for mid to C-level roles including CEO, COO, Directors, and medical professionals across U.S. and\u000aIndia offices, aligning talent strategy with organizational growth.\u000a• Built and currently lead a handpicked team of Project Managers, Project Coordinators, and Data Analysts; together, we manage multiple\u000ahigh-priority projects in parallel while I represent the team and report directly to the Founders on progress, impact, and strategic\u000aalignment.\u000a• Led strategic, cross-functional initiatives across Sales, IT, HR, Media, Finance, and RCM.\u000a• Drove new unit launches, international expansion, restructuring, and executive reporting.\u000a• Integrated automation, AI, Tableau, and Power BI to increase efficiency by 40% and quality by 25%.\u000a• Negotiated vendor contracts (20% savings) and improved team retention by 30%.\u000aProject Manager Jul 2021 – Jul 2022\u000a• First internal promotion to PM role within 2 years; led profit and nonprofit projects with 100% on-time delivery.\u000a• Supervised a team of 15+ and improved workflows by 35%.\u000a• Led client onboarding, solution design, and executive presentations.\u000aSenior Executive – Market Research & Analytics May 2020 – Jun 2021\u000a• Promoted twice in one year; implemented dashboards and reports using Power BI, Tableau, and SPSS.\u000a• Supported KPI definition, data validation, and cross-functional research protocols.\u000aTrainee Nov 2019 – Apr 2020\u000a• Executed U.S. healthcare research with 95% accuracy.\u000a• Built institution datasets and contributed to national-level market intelligence.\u000aConcept Ventures Pvt. Ltd.– Gurugram, India\u000aSecondary Market Research Executive June 2019-Nov 2019\u000a• Conducted real estate market research in Indian metros using Excel macros and formulas.\u000a• Led 25-person team on SquareYards portal, ensuring QC, submissions, and training.\u000a• Managed Canadian financial research on credit/debit cards, and built transaction reports.\u000aSKILLS & CORE COMPETENCIES\u000aProject Management & Analytics Tools: Jira, Trello, Asana, Microsoft Project, Monday.com, Tableau, Power BI, SPSS, Excel\u000aMethodologies: Agile, Scrum, Waterfall, Kanban, Chat GPT, AI tools\u000aSoft Skills: Leadership, Communication, Time Management, Problem-Solving\u000aStrategy & Business Ops: Budgeting, OKRs, GTM planning, cross-functional alignment\u000aClient Engagement: Stakeholder retention, onboarding, satisfaction metrics, communication\u000aFounder’s Office & Leadership: Board reporting, M&A support, strategic projects, liaison roles\u000aEDUCATION & CERTIFICATIONS\u000aMaharshi Dayanand University – Rohtak, Haryana - B.A. (Hons.) Economics Aug 2015 – Aug 2018\u000aGoogle Project Management Specialization – Jul 2024 | Microsoft Career Essentials in Project Management – Jun 2024\u000aLean Six Sigma Foundations (LinkedIn Learning) – Jun 2024 | Microsoft AI Product Manager – May 2025\u000aPROFESSIONAL PROJECTS\u000a1. The Medicine Mentors Podcast, USA: Led the end-to-end podcast lifecycle, including concept development, guest acquisition, production,\u000aand distribution. Reduced manual effort by 30% and costs by 20%. Managed global teams, growing it to 10M+ listeners and establishing it as a\u000athought leadership platform.\u000a2. American Association for Cancer Research (AACR) & American Society of Clinical Oncology (ASCO), USA: Oversaw end-to-end execution\u000aof a healthcare podcast with AACR and ASCO, from research and scripting to post-production. Streamlined guest workflows and internal\u000aprocesses, cutting setup time by 30%. Collaborated with senior oncology experts to ensure brand and content alignment across teams.\u000a3. Larkin University, Florida, USA: Managed end-to-end video case studies with 30+ oncology experts, overseeing research, interviews, scripting,\u000aand production coordination across India and the U.S. Enhanced engagement by 50% through strategic storytelling and structured interview\u000adesign.\u000a4. COVID Documentary (India, USA, Philippines): Led international COVID-19 documentary production, managing research, interviews, and\u000avendor negotiations across 3 countries. Delivered a high-impact film while reducing costs by 25% through process optimization.'),NULL);
INSERT INTO candidates VALUES(823,9,NULL,'Ankur Seth','ankurseth55@gmail.com','82',NULL,NULL,'Ankur Seth is an experienced professional with 10 years in financial research, investment banking, and corporate finance, demonstrating strong analytical, communication, and project execution skills. He has a proven track record in data analysis, financial modeling, and stakeholder management.','pending','row_7','2025-11-20 11:53:50','2025-11-25 11:00:55','-9810765823',NULL,NULL,unistr('Ankur Seth\u000aE ma i l I D : a n k u r s e t h 5 5 @ g ma i l . c o m\u000aLinkedIn URL: h t t p s : / / w w w . l i n k e d i n . c o m/ i n / a n k u r - s e t h - 7 8 3 3 6 5 5 1 /\u000aPermanent Address: House number 58, sector 7, Gurgaon (122001), Haryana Contact Details: +91-9810765914\u000aEducation:\u000aExamination / Degree Year School / Institute (University) CGPA / %\u000aMBA (Finance) 2012 ICFAI Business School, Hyderabad (IFHE, Hyderabad) 7.1\u000aBBA (General) 2010 Maharshi Dayanand University, Rohtak 74.6%\u000aClass XII (CBSE) 2005 Blue Bells Model Senior Secondary School, Gurgaon 72.2%\u000aClass X (CBSE) 2003 Blue Bells Model Senior Secondary School, Gurgaon 79.8%\u000aTotal Work Experience Summary:\u000a✓ 10 years of experience in Business Development, Business Research, Corporate Finance, Credit Research, Due Diligence, Equity\u000aResearch, Financial Planning & Analysis (encompassing annual operating plans, budgeting, forecasting and variance analysis), Funds\u000aRaising, Investment Banking, Investor Relations, Macroeconomic Research, Market Research, and Mergers & Acquisitions (M&A)\u000a✓ Excellent stakeholders-management skills with experience in working with senior stakeholders around the globe\u000a✓ Substantial exposure in working with financial investors such as corporate venture capital (CVC) arms, debt funds, family offices,\u000afinancial institutions, private equity and venture capital\u000a✓ Extensive team-handling experience, which includes mentorship and supervision\u000a✓ Adept at using databases such as Adaptive Insights, Bloomberg, Capital IQ, Crunchbase, Factiva, FactSet, Grata, HubSpot, Oracle,\u000aPitchBook, Refinitiv Eikon, SAP, Tally and ThomsonOne\u000a✓ Well-acquainted with Excel, Google Docs, Google Sheets, Google Slides, Power BI, PowerPoint, Tableau and Word\u000aWork Experience Details:\u000a1) Africare Global (AG) (Ahmedabad) (March 2024–November 2024)\u000aAssistant General Manager (AGM) (Corporate Finance)\u000aWorked as an AGM at AG, which is a conglomerate of specialized companies, offering market-leading healthcare-and-allied products and\u000aservices, ranging from clinics, hospitals, fertility centres, a pharmaceutical manufacturing facility and Insurance. Key roles and\u000aresponsibilities were:\u000a✓ Gathered financial and operational data from the group of companies\u000a✓ Consolidated and reviewed performance of various business units\u000a✓ Crunched data and created presentation decks which were used by AG for funds raising and strategic decision-making\u000a✓ Analysed and presented organization''s large data sets to the management, to provide actionable insights\u000a✓ Recommended process improvements to increase a business''s efficiency\u000a2) ComCap (Gurgaon) (November 2021– December 2023)\u000aSenior Analyst (Investment Banking)\u000aWorked as a Senior Analyst at ComCap, which is a boutique investment bank headquartered in San Francisco, and focuses on deals in\u000aAutomotive Software, Ecommerce, FinTech, Grocery Technology, Logistics & Supply Chain, Marketing and Advertising Technology,\u000aMarketplaces, Tech-enabled Services sectors, etc. Some of the job responsibilities were:\u000a✓ Created confidential information memorandums, financial models, investment teasers, pitch decks and valuation reports\u000a✓ Worked on fundraising (debt & equity) deals, whose size ranged from $1M to $30M; M&A deals (buy-side & sell-side) size ranged\u000afrom $40M to $125M; in total, I worked on 10 to 12 funds raising and M&A deals\u000a✓ Prepared lists of prospective financial (CVC arms / family office / private equity / venture capital) and strategic buyers for sell-side\u000aclients by running relevant screens on Capital IQ, Crunchbase, Grata and PitchBook; similarly identified targets for buy-side clients\u000a✓ Lead investors (financial and strategic) outreach and relationship management through HubSpot (which is a CRM platform or tool)\u000a✓ Developed strategic communication plans and reporting for prospective investors\u000a✓ Collaborated closely with founders and leadership team during fundraising rounds\u000a✓ Maintained and updated investor CRM, and data room platforms\u000a✓ Managed due diligence processes, and ensured timely delivery of documents and data\u000a✓ Prepared trading and transaction comparable multiples\u000a✓ Prepared thematic reports which were published on the company’s website for business development purpose\u000a✓ Ran screens on different databases to do precedent and private placement transactions analysis for a company or sector or subsector\u000a✓ Prepared marketing materials in the form of Google Slides for ComCap’s top-level investment bankers; those presentations were used\u000ain globally renowned conferences such as Money 20/20 and Groceryshop\u000a\u000aAnkur Seth\u000aE ma i l I D : a n k u r s e t h 5 5 @ g ma i l . c o m\u000aLinkedIn URL: h t t p s : / / w w w . l i n k e d i n . c o m/ i n / a n k u r - s e t h - 7 8 3 3 6 5 5 1 /\u000aPermanent Address: House number 58, sector 7, Gurgaon (122001), Haryana Contact Details: +91-9810765914\u000a3) WNS (Gurgaon) (April 2021–August 2021)\u000aSenior Analyst (Investment Banking)\u000aWorked as an FTE-cum-supervisor with one of the leading global Investment Banking companies to execute and manage projects for\u000abankers from the UK and the US locations. Job responsibilities were:\u000a✓ Preparation of company and strip profiles, and pitch books\u000a✓ Preparation of trading and transaction comparable multiples\u000a✓ Financial and operational benchmarking through companies’ filings, and analysts’ / brokers’ reports\u000a✓ Preparation of a daily project tracker to allocate projects / work among team members\u000a✓ Mentored and supervised work of team members\u000a✓ Ensured completion of assigned tasks within strict timelines with zero error\u000a4) KPMG (Gurgaon) (April 2019–November 2019)\u000aConsultant (Financial Research)\u000aWorked as an FTE to execute financial benchmarking projects for stakeholders from the UK. The projects typically encompassed the\u000afollowing steps:\u000a✓ Peers shortlisting: An exhaustive list (includes business description, primary industry, headquarters, revenue, gross and EBITDA\u000amargins, etc.) of relevant public and private peers operating in a particular industry / sub-industry and geography / ies was created, and\u000athen shared with a stakeholder / requestor for approval\u000a✓ Data collection: Post approval, a detailed excel databook file was prepared. The databook incorporated the following financial KPIs:\u000a➢ Revenue CAGR vs. gross margin and revenue CAGR vs. EBITDA margin; gross, EBITDA, EBIT and net margins trends\u000a➢ Operating, SG&A, R&D, G&A, personnel, depreciation, capital expenditure and rental expenses as a % of revenue\u000a➢ Capital expenditure/depreciation, and net working capital and free cash flow as a % of revenue\u000a➢ Cash conversion cycle, days sales outstanding, days inventory outstanding, days payables outstanding\u000a➢ Debt/equity, return on assets, return on equity and current ratios\u000a➢ Valuation multiples such as P/E, EV/sales, EV/EBITDA, PEG ratio, etc.\u000a✓ Storyboarding: Data captured in the above step was then qualitatively analysed and presented in PowerPoint\u000a5) [24]7.ai (Bengaluru) (July 2017–March 2019)\u000aAssistant Manager (Financial Planning and Analysis, and Financial Research)\u000aWorked as an FTE within Finance team at a BPO-cum-IT company. The job responsibilities included:\u000a✓ Monthly review and question (for variances) actual and rolling forecast numbers from revenue and expenses files shared by regional\u000ateam’s and business unit’s analysts. Post explanations from them, profit & loss statement was consolidated. The exact process was\u000afollowed for quarterly Board of Directors meeting and annual operating plan\u000a✓ Prepared monthly, quarterly and annual operating plan decks, which were shared with VP (Finance), CFO and CEO of the company.\u000aThe decks included detailed P&L statement (at segmental level as well) and headcount analysis. The analysis captured qualitative\u000aexplanations of variances (sequential and year-on-year) between months, quarters and fiscal years\u000a✓ Competitors’ profiling with a major emphasis on financial performance. A peer’s profile comprised ensuing sections:\u000a➢ Business and offerings overview; public market overview\u000a➢ Forward valuation multiples; analysts’ estimates, outlook and comments / viewpoints\u000a➢ Shareholders’ ownership profile; management’s and board of directors’ background\u000a✓ Financial benchmarking of the organisation vis-à-vis its peers. The benchmarking parameters included:\u000a➢ P&L comparables: Revenue growth, COGS %, gross margin, R&D %, S&M %, G&A %, EBITDA and EBIT margins,\u000aEBITDA/interest expense, PBT and PAT margins, etc.\u000a➢ BS comparables: Debt -to-equity, total assets-to-total liabilities, etc.\u000a➢ BS and P&L comparables: Net debt-to-EBITDA, revenue/employee, ROA, ROE, etc.\u000a➢ CF and P&L comparables: FCF margin, FCF margin + revenue growth, etc.\u000a6) Evalueserve (Gurgaon) (February 2015–January 2017)\u000aSenior Business Analyst (Financial Research)\u000aWorked as an FTE with one of the world’s supermajor oil and gas companies to analyse financial health of its suppliers, primarily for\u000aidentification of negotiating levers. Details of type of projects are illustrated below:\u000a\u000aAnkur Seth\u000aE ma i l I D : a n k u r s e t h 5 5 @ g ma i l . c o m\u000aLinkedIn URL: h t t p s : / / w w w . l i n k e d i n . c o m/ i n / a n k u r - s e t h - 7 8 3 3 6 5 5 1 /\u000aPermanent Address: House number 58, sector 7, Gurgaon (122001), Haryana Contact Details: +91-9810765914\u000a✓ Studied financial health of suppliers which encompassed:\u000a➢ Top-and-bottom-line performances\u000a➢ Liquidity position (including undrawn revolving credit facilities)\u000a➢ Gearing trend (including debt maturity schedule and breach of covenants)\u000a➢ Credit rating downgrade / upgrade or change in rating outlook or both by any of the world’s top three credit rating agencies\u000a➢ Management outlook and guidance\u000a➢ Encapsulating what globally renowned research houses’ / investment banks’ analysts are conveying in their reports\u000a✓ Quarterly prepared and updated financial models to forecast and analyse year-end cash position (including working capital and capital\u000aexpenditure requirements, assets sale / disposal, debt repayments, equity and debt issuances, dividend payments, etc.) of suppliers\u000a✓ On a quarterly basis, prepared earnings reports, which included:\u000a➢ Analysis on market capitalisation, order backlog and intake trend\u000a➢ How top-and-bottom-lines are expected to perform in short-to-medium-term\u000a➢ Strategies being and to be implemented (for example: headcount reduction and other rigorous cost control measures, disposal\u000aof non-core businesses or any of the divisions, geographic diversification of business, etc.)\u000a➢ Market share trend and any noticeable recent developments\u000a7) The Smart Cube (Noida) (April 2012–January 2015)\u000aSenior Associate (Financial and Macroeconomic Research)\u000aWorked as an FTE with diverse clients to strengthen existing relationships. Details of some of my past projects are illustrated below:\u000a✓ Worked with a London-based restructuring-consulting firm to co-author a research paper on the implementation of ‘Good-Bank–Bad-\u000aBank’ financial system stabilisation models used by ailing banking systems in Ireland, Iceland and Denmark\u000a➢ The research paper involved studying the impact of economic crisis in each of the three economies, how the crisis led to a\u000acreation of a Good-Bank and a Bad-Bank, valuation and accounting of toxic assets transferred to a bad bank, and operational\u000aperformance analysis (measured through liquidation of toxic assets) of a bad bank\u000a✓ Detailed credit research on Natixis, a French bank, covering the following aspects:\u000a➢ The qualitative part comprised analysis of credit health of the bank along with a study of the broad industry and relevant\u000amacroeconomic trends that had an influence on Natixis’ credit profile\u000a➢ The quantitative part captured a short-term credit score for the bank which was an aggregation of separate scores on several\u000afinancial and operational parameters. This part was supplemented with a detailed financial model\u000a✓ Worked with a Swiss private bank to co-author a macroeconomic report on China to assess whether the economy was heading towards\u000aa ‘hard landing’\u000a✓ Wrote a short report on analysing the impact of ‘quantitative easing—an unconventional monetary policy tool’ on the US economy\u000a✓ Authored a report in November 2014 to study whether the 2015 global economic forecasts will be revised upwards or downwards\u000a✓ Worked with the asset management division of a UK-based fund manager, to quarterly prepare counterparty credit risk reports for its\u000atop 30 exposures\u000a✓ Co-authored blogs on ‘Are we witnessing Tech Bubble 2.0’, ‘Impact of US Municipalities’ bankruptcies on its Municipal bond\u000amarket’, ‘US fiscal cliff’, ‘Platinum price outlook’ and ‘China’s burgeoning investment in Africa’ for company’s prospective clients\u000aInternship:\u000aGlobe Capital Market Ltd. [February 2011−May 2011]\u000aStudied the impact of Union Budget on Indian economy from announcements made for Agriculture, BFSI, Infrastructure, IT and Telecom\u000asectors. The objective was to analyse whether the announcements made would propel the economy forward or backward or keep it stagnant.\u000aProfessional and Academic Achievements:\u000a✓ Received a ‘Quarterly Champion’ certificate at [24]7.ai for my work on competitors’ analysis.\u000a✓ Received a ‘Pat on the Back’ certificate at Evalueserve for building a financial model which was used extensively in the team\u000a✓ Secured a ‘Cheer’ award and a ‘Smart Team’ award at The Smart Cube for my contribution on a client account\u000a✓ Won various intra-college cricket tournaments in IBS, Hyderabad\u000a✓ Came twice among top 15 students in second and third semesters of BBA at university level'),NULL);
INSERT INTO candidates VALUES(824,9,NULL,'NIVED P','nivedp96@gmail.com','86',NULL,NULL,'Strategy Manager with 5+ years of experience leading high-impact initiatives and driving business results across technology, FMCG, and education sectors. Proven expertise in strategic planning, operational excellence, and managing cross-functional projects, with a strong background as Chief of Staff to CEO.','pending','row_8','2025-11-20 11:53:50','2025-11-25 11:00:55','#ERROR!',NULL,NULL,unistr('NIVED P\u000a+91 96332 28209 | nivedp96@gmail.com | nived0956@gmail.com\u000aBengaluru, India | https://www.linkedin.com/in/nived-p-41b6b6137/\u000aPROFILE SUMMARY\u000aStrategy Manager with 5+ years of experience leading high-impact initiatives, aligning\u000aorganisational priorities, and delivering measurable business results across technology, FMCG,\u000aand education sectors. Proven expertise in designing and executing multi-year strategies,\u000amanaging transformation programs, and embedding performance frameworks that improve\u000aefficiency and profitability. Skilled in coordinating cross-functional teams, streamlining\u000acommunication, and overseeing mission-critical projects from planning to completion. Adept at\u000aleveraging data insights, market intelligence, and structured governance to guide strategic\u000adecisions and accelerate organisational outcomes. Recognised for precision in execution,\u000astakeholder trust, and the ability to convert strategic vision into sustained business impact in\u000adynamic, high-growth environments\u000aCORE COMPETENCIES\u000aStrategic Planning & Execution, Business Transformation & Process Excellence, Executive\u000aStakeholder Management, Business Analytics & Data Visualization, Project & Program\u000aManagement, Product Development & Go-to-Market Strategies, Risk Assessment & Mitigation,\u000aP&L and Budget Management, Cross-functional Team Leadership, Operations Management,\u000aPricing Strategy\u000aPROFESSIONAL EXPERIENCE\u000aStrategy Manager | Chief of Staff to CEO | Apr 2023 – Present\u000aHIPPOCAMPUS LEARNING CENTRES PVT. LTD. – Bengaluru\u000a• Serve as the CEO’s strategic partner in defining organizational direction, ensuring all business\u000aunits operate in alignment with the corporate vision.\u000a• Drive the annual and quarterly strategic planning cycle, setting measurable OKRs for leadership\u000ateams and instituting review cadences to track performance.\u000a• Drive cross-functional projects to align business units, systems, and processes with overall\u000aenterprise objectives\u000a• Successfully led end-to-end project delivery by identifying gaps, structuring efficient processes,\u000aand executing within defined timelines to achieve business impact\u000a•Conduct scenario modelling and financial sensitivity analysis to guide investment decisions, risk\u000amitigation, and long-term growth planning.\u000a\u000a• Designed enterprise-grade dashboards in Power BI and Tableau integrated with SQL-based data\u000apipelines, enabling real-time decision-making for C-suite.\u000a• Coordinated cross-functional teams to deliver projects on time by defining scope, tracking\u000amilestones, and ensuring stakeholder alignment\u000a• Conducted research and analysis on industry trends, competitors, and market opportunities to\u000asupport CEO-level decision-making\u000a• Managed project documentation, timelines, and risk assessments while providing regular status\u000aupdates to internal and external stakeholders, ensuring smooth execution.\u000a• Negotiate high-value vendor contracts and strategic partnerships, delivering up to 20% cost\u000areductions.\u000a• Identified project risks and dependencies early and implemented proactive mitigation plans,\u000aensuring on-time delivery and minimizing business disruption\u000a• Conducted scenario and sensitivity analyses to evaluate project viability and resource allocation\u000a• Implement Just-In-Time (JIT) supply chain management, reducing inventory holding costs by\u000a18% and improving cash flow.\u000a• Conduct in-depth market analysis to identify and prioritize expansion into high-potential\u000aregions, presenting investment cases to the Board.\u000a• Develop integrated financial models covering P&L, cash flow, and scenario planning to guide\u000aexecutive decision-making.\u000a• Build and implement an enterprise risk management framework covering operational,\u000areputational, and compliance risk areas.\u000a• Represent the CEO in high-level engagements with government agencies, NGOs, and donors,\u000asecuring collaborations worth over Rs. 5 Cr.\u000a• Lead organizational change management programs, including leadership capability building,\u000aemployee engagement initiatives, and cross-functional training.\u000aACHIEVEMENTS\u000a• Delivered 25% YoY cost savings through operational efficiency projects.\u000a• Successfully designed and executed three enterprise-level transformation programs within 18\u000amonths.\u000a• Recognized for C-suite support excellence by CEO for accelerating decision-making and\u000aenhancing operational transparency. Awarded Best Employee – 2024–25 for outstanding\u000acontribution to strategic initiatives and business performance improvement\u000aStrategy Operation/ Senior Business Analyst | Aug 2018 – May 2021\u000aG42 CLOUD TECHNOLOGY LLC – Abu Dhabi, UAE\u000a• Partnered with senior leadership to identify business gaps in cloud adoption, conducted\u000astakeholder workshops, and translated business needs into functional and non-functional\u000arequirements for scalable technology solutions\u000a• Led business analysis for cloud service utilization, client adoption trends, and revenue streams,\u000aidentified gaps in customer engagement and delivered insights that improved adoption rates and\u000amarket share\u000a\u000a• Designed, documented, and maintained business process maps, operating models, and data flow\u000adiagrams to support cloud system development, automation, and continuous process improvement\u000a• Collaborated with product and marketing teams to analyze enterprise customer data, industry\u000abenchmarks, and usage behavior, shaping go-to-market strategies for cloud service offerings\u000a• Partnered with finance teams to conduct cost optimization and margin analysis of cloud\u000aservices, enabling pricing model enhancements and subscription package improvements\u000a• Developed financial and scenario models to guide cloud investment decisions, new product\u000alaunches, and strategic planning for leadership\u000a• Conducted in-depth market research, competitor benchmarking, and product performance\u000aanalysis in the cloud and AI ecosystem to support business growth and expansion strategies\u000a• Performed trend and variance analysis across multi-dimensional business factors (usage,\u000alocation, industry verticals), uncovering patterns to drive customer retention and revenue growth\u000a• Built and maintained interactive dashboards and KPI reports that provided real-time visibility\u000ainto customer usage, operational performance, and financial metrics, accelerating leadership\u000adecision-making\u000a• Managed full lifecycle of cloud transformation projects: scope definition, cost-benefit analysis,\u000abacklog and sprint planning, testing, launch, and post-implementation support\u000a• Developed and executed pricing and packaging strategies for cloud services by analyzing\u000acompetitor benchmarks, customer demand, and cost structures, improving margins and customer\u000aacquisition\u000a• Managed project risks, dependencies, and change requests while embedding compliance, data\u000agovernance, and risk management frameworks across business and technology functions\u000a• Collaborated with cross-functional teams to ensure business requirements were clear, feasible,\u000aand successfully delivered within agreed timelines and quality standards\u000a• Reviewed and validated vendor contracts, service-level agreements (SLAs), and purchase\u000arequests, ensuring compliance with procurement policies and alignment with business and\u000atechnology objectives\u000aBusiness Strategy Intern | Jul 2022 – Aug 2022\u000aMENMITSU PVT. LTD. – Delhi, India\u000a• Assisted in gathering and documenting business requirements for AI/ML-driven solutions by\u000aconducting stakeholder interviews and translating needs into user stories and process flows.\u000a• Performed exploratory data analysis on structured and unstructured datasets to identify patterns,\u000atrends, and anomalies supporting model development.\u000a• Collaborated with data scientists and engineers to validate AI model outputs against business\u000arequirements, ensuring accuracy and usability.\u000a• Supported creation of dashboards and visualizations (Power BI/Tableau/Python) to present\u000ainsights on model performance and business impact.\u000a• Researched industry use cases of AI applications, benchmarking competitors, and preparing\u000areports to guide product strategy and roadmap.\u000a• Documented workflows, process changes, and knowledge repositories to support scaling of AI\u000asolutions across business units.\u000a\u000aEDUCATION & CERTIFICATIONS\u000a• MBA (PGDM) – International Trade & Logistics | IMT Ghaziabad – IMT Dubai | 2021–2023\u000a• B.Tech – Electronics & Communication | Cochin University of Science & Technology | 2014–\u000a2018\u000a• Disruptive Strategy – Harvard Business School Online | 2023\u000a• Lean Six Sigma Black Belt – Knowledge Academy, UK | 2024\u000a• Advanced Business Analytics Specialization 2024\u000aTECHNICAL SKILLS\u000a• Data Analytics & BI Tools: SQL, Power BI, Tableau, Minitab, SPSS, KNIME, R Programming\u000a• Project Management Tools: MS Project, JIRA, Asana\u000a• MS Office Suite: Advanced Excel, PowerPoint, Word\u000aLANGUAGES & INTERESTS\u000a• Languages: English, Malayalam, Hindi\u000a• Interests: Cricket analytics, Strategy simulations, Business case competitions'),NULL);
INSERT INTO candidates VALUES(825,9,NULL,'Sharuk T','RNSHARUKH21@GMAIL.COM','83',NULL,NULL,'Strategic Chief of Staff and Founder’s Office operator with over 5 years of experience driving GTM execution and operational excellence in high-growth environments. Adept at steering initiatives in fast-paced, ambiguous settings and delivering systems that accelerate strategic impact.','pending','row_9','2025-11-20 11:53:50','2025-11-25 11:00:55','#ERROR!',NULL,NULL,unistr('Sharuk T\u000aCHIEF OF STAFF | STRATEGIC OPERATOR | FOUNDER''S OFFICE\u000a📍 Hyderabad | 📧 RNSHARUKH21@GMAIL.COM | 📞 +91 8121807607\u000aExecutive Summary\u000aStrategic Chief of Staff and Founder’s Office operator with 5+ years of success driving GTM execution,\u000aoperational excellence, and C-suite leverage across high-growth fintech and political consulting ecosystems.\u000aOrchestrated India’s largest IPO, scaled the Product & Strategy team from 3 to 18 members, and delivered\u000across-functional alignment across GTM, Product, IT, and Marketing for multiple B2B and B2C fintech\u000alaunches. Deployed proprietary playbooks-including User Ecstasy (UC), the Hooked Method, and Performance\u000aFriction frameworks-to maximize adoption, retention, and marketplace scale. I expertly combine deep research,\u000astakeholder engagement, and high-velocity operations. Consistently distills socio-political and market insights\u000ainto actionable plans, leveraging data-driven reporting and agile frameworks for large-scale project success.\u000aAdept at steering initiatives in fast-paced, ambiguous environments, fostering coordination from boardroom to\u000agrassroots, and delivering 0→1 systems that accelerate strategic impact and organizational growth.\u000aProfessional Experience\u000aFounder''s Office – Operations | IPAC Consulting | Feb 23 – Jun 24\u000aKey Achievements & Responsibilities:\u000aPartnered directly with founders to lead company-wide execution, optimize processes, and build high-\u000aagility road-maps for major business lines.\u000a· Spearheaded business process redesign, removing bottlenecks and increasing org-wide productivity\u000a· Managed multi large scale projects and cross-functional teams, delivering ahead of deadlines with high\u000acoordination.\u000a· Established agile reporting, OKR frameworks, and UC-based retention systems adopted company-\u000awide.\u000a· Delivered actionable insights and dashboards, influencing strategic pivots and C-suite decision making.\u000a· Launched CXO OKR system, increasing team alignment and quarterly goal attainment from 60% to\u000a85%\u000aChief of Staff – Products & Strategy | KFintech | Nov 21 – Dec 22\u000aKey Achievements & Responsibilities:\u000aActed as strategic right-hand to C-suite leaders, scaling high-impact product, GTM, and operational\u000ainitiatives across fintech verticals.\u000a· Scaled Product & Strategy team from 3 to 18 members, engineering best-in-class alignment across\u000aGTM, Product, IT, and Marketing.\u000a· Orchestrated India’s largest IPO, managing stakeholder reporting, compliance, and investor\u000acommunications under high-stakes timelines.\u000a· Drove end-to-end product launches, deploying Hooked Method and Performance Friction frameworks\u000ato fuel user adoption and retention.\u000a· Implemented business intelligence dashboards and data-driven reporting, accelerating decision velocity\u000aby 30%.\u000a· Steered multidisciplinary teams in delivering strategic projects and transformation initiatives on\u000aschedule and within budget.\u000a· Reduced processing time by 40% via workflow automation and AI-driven dashboards\u000a\u000aExecutive Associate – Business & Strategy | Infosys BPM | Apr 18 – Jan 20\u000aKey Achievements & Responsibilities:\u000aSupported BU leadership and executives in delivering high-stakes strategic projects and streamlined\u000abusiness operations.\u000a· Led business reporting and analytics, providing critical insights that guided decision-making and\u000aoperational pivots.\u000a· Managed diverse, cross-functional teams in executing process improvements—enhancing efficiency\u000aand reducing turnaround times by 15%.\u000a· Developed and rolled out SOPs and operational frameworks, raising execution standards and ensuring\u000arigorous compliance.\u000a· Coordinated leadership briefings, stakeholder meetings, and executive communications for seamless\u000aalignment and visibility.\u000aSenior Process Executive | Cognizant | Aug 17 – Feb 18\u000aKey Achievements & Responsibilities:\u000aOversaw process optimization, talent development, and workflow automation for a leading tech client.\u000a· Managed new product development operations, overseeing 16% of total manpower for a major\u000aproduct line.\u000a· Designed and delivered on-site hiring and training for SMEs across India, boosting productivity and\u000ascaling operational knowledge transfer.\u000a· Spearheaded quality assurance, SOP documentation, and data management—ensuring delivery\u000aexceeded client benchmarks.\u000a· Leveraged GIS-based product development and workflow automation to drive measurable operational\u000aefficiency improvements.\u000aAssociate Analyst | GlobalLogic | Sep 16 – May 17\u000aKey Achievements & Responsibilities:\u000aWorked as a Production & Quality Analyst for a major tech client, specializing in policy-making and\u000aworkflow optimization.\u000a· Led spatial data management initiatives, streamlining production processes and enhancing data\u000aaccuracy by 10%.\u000a· Resolved operational conflicts and authored comprehensive process documentation, supporting\u000ascalable workflow improvements.\u000a· Leveraged research and analytics to inform leadership decisions and drive quality standards across\u000adeliverables.\u000aCore Competencies\u000a· GTM Strategy & Execution\u000a· C-Suite Stakeholder Management\u000a· Program Management\u000a· Business Intelligence & Analytics\u000a· Process Optimization\u000a· Agile/OKR Frameworks\u000a· AI-driven Workflow Automation\u000a· GTM Playbooks\u000a· Investor/Board Communication\u000a· Cross-functional Leadership\u000a· Data-Driven Decision Making\u000a· Performance Friction Playbooks\u000a· Product Launches\u000a· Change Management\u000a· Confidential Correspondence\u000a· Strategic Initiatives\u000aEducation\u000aB.Tech, ECE, JNTU Anantapur, 2010–14'),NULL);
INSERT INTO candidates VALUES(826,9,NULL,'T D Surendra','Suren.td149@gmail.com','82',NULL,NULL,'Highly experienced Executive & Personal Assistant with over 10 years in operations, executive support, and project coordination, demonstrating strong communication and analytical skills.','pending','row_10','2025-11-20 11:53:50','2025-11-25 11:00:55','+91 8121080565',NULL,NULL,unistr('Employment Details\u000aProfile Summary:\u000a• 10+ years of rich experience in the Executive & Personal Assistant and\u000aexpertise in Operations involving Admin, maintaining records, ensuring timely\u000adeposits, and implementing financial procedures projected towards\u000aorganizational goals to maximize profitability.\u000a• Excellence in streamlining Organizing Board meetings, ensuring delivery with\u000aaccuracy and maintaining effective employee relations by guiding them in\u000amatters pertaining to all the reports, Statutory Deductions and\u000aReimbursements.\u000a• Result driven professional with over 6+ years of comprehensive experience in\u000ainternational (Offshore)- USA, Canada and Japan.\u000a• High-energy professional with capability in achieving business growth\u000aobjectives with excellent communication, people management, analytical and\u000aproblem-solving skills.\u000aEducation:\u000a• Bachelors of Technology (CSE) from Bapatla Engineering College in 2015- AP\u000a• Diploma (CME) from Sri Venkateswara Polytechnic in Tirupathi-2011\u000a• SSC (10th- Class) from ZPH School in Chirala-AP-2008\u000aCertifications:\u000a• Microsoft Excel Certification in 2022\u000a• Chat GPT Certification in 2023\u000a• Leadership Certification through Linked-in 2023\u000a• BPM (Bullet Proof Manager)- in 2024\u000a• Shorthand typing (45 WPM)\u000aMay’25- Present with Sree MM Group- Assistant Manager (EA)\u000aJun’20- May’25 with Thryve Digital Health- Associate Manager (EA & HR)\u000aMar’19- Mar’20 with Inspirisys - Team Lead (EA & PA)\u000aMar’17-Mar’19 with SAKSOFT - Consultant (EA & PA)\u000aApr’15 -Mar’17 with Kyyba Pvt Ltd- Senior Executive (HR & PA)\u000aSree MM Group- (RJY, HYD and Kerala)- Contract Opportunity:\u000aRoles & Responsibilities:\u000a• Direct reporting to MD & ED.\u000a• Provided end-to-end executive support to MD & ED, including calendar, communication, and task management\u000a• Coordinated high-level meetings, prepared agendas, minutes, and ensured timely follow-ups on decisions\u000a• Managed confidential communication and business-critical documentation with discretion\u000a• Handled complex domestic and international travel arrangements and logistics\u000a• Acted as a liaison between MD/ED and internal teams, stakeholders, and board members\u000a• Supported in strategic planning, business reviews, dashboards, and executive reporting\u000a• Facilitated cross-functional coordination and tracking of key leadership projects\u000a• Maintained high standards of professionalism, time management, and operational efficiency\u000aThryve Digital Health- (Hyderabad & Chennai):\u000aRoles & Responsibilities:\u000a• Direct reporting to CEO & Director\u000a• Preparing for the daily agenda for CEO.\u000a• Scheduling & fixing up appointments (Personal & Official) for CEO\u000a• Scheduling Team Meetings & Business Clients meetings as per CEO\u000a• Coordinating with the team members for getting Important Data & Reports of the on- going projects & submitting the same to the\u000aT D Surendra\u000aPh: #+91 8121080565 Email ID- Suren.td149@gmail.com\u000aKey Expert Areas\u000a~ Secretary Operations\u000a~ Organizing Meetings\u000a~ Preparing reports for MOM\u000a~ Arrange Appointments\u000a~ Travel Arrangement\u000a~ Vender management\u000a~ Project Management Skills\u000a~ Stakeholder Management\u000a~ Time Office Management\u000a~ MS Office and ERP\u000a~ Operations & Admin Activities\u000a~ Employee Engagement\u000aActivities\u000a\u000aCEO & respective project leads.\u000a• Maintaining daily, weekly and monthly reports (MS Office- Word, Excel and PowerPoint presentation)\u000a• Arranging Travel Arrangements for the Business Visitors\u000a• Answer telephone calls in the Executive Office as and when required.\u000a• Monitoring & record keeping of any important documents and files\u000a• Managing daily calendar & setting up reminders for meetings and preparing for the MOM.\u000aInspirisys Solutions (LTD) - (Chennai & Bangalore):\u000aRoles & Responsibilities:\u000a• Direct reporting to CHRO\u000a• Maintain CHRO’s agenda and assist in planning appointments, board meetings, conferences, etc.\u000a• Organizing meetings and coordinating with the Department Head & the management.\u000a• Scheduling & fixing up appointments (Personal & Official)\u000a• Meticulous attention to detail and the ability to work well under pressure.\u000a• Interpersonal skills and the ability to work with people at all levels.\u000a• Excellent organization and time management.\u000a• Checking documents submitted by all departments and record when use the stamp\u000a• Good verbal and written communication skills\u000a• Maintaining daily, weekly and monthly reports.\u000a• Arranging Travel Arrangements for the Business purpose.\u000a• Receive and screen phone calls and redirect them when appropriate\u000a• Handle and prioritize all outgoing or incoming correspondence (Drafting e-mail, letters)\u000aSAKSOFT Limited- (Chennai & Pune):\u000aRoles & Responsibilities:\u000a• Direct reporting to Sr. VP\u000a• Organizing meetings and coordinating with the Vice President.\u000a• Preparing reports, presentations, and correspondence accurately and swiftly.\u000a• Answering and screening telephone calls, and responding to emails, messages, and other correspondence.\u000a• Managing a busy calendar, meeting coordination, and travel arrangements.\u000a• Booking of Flights and Hotels for Domestic & International Sector\u000a• Excellent organization and time management.\u000a• Keeping and maintaining accurate record of all important papers and other personal correspondence on Behalf of the GM.\u000a• Proficient in Microsoft Office, and business communication software.\u000a• Good verbal and written communication skills\u000a• Maintaining daily, weekly and monthly reports.\u000aKyyba Pvt Ltd- (Chennai & Bangalore):\u000aRoles & Responsibilities:\u000a• Direct reporting to Vice President-VP\u000a• Assisting the Director in day-to-day office work.\u000a• Managing the data properly.\u000a• Preparing reports as per the requirement.\u000a• Maintain a calendar of official appointments.\u000a• Set up and coordinate meetings and conferences.\u000a• Maintain hard copy and electronic filing system for personal and official documents.\u000a• Maintain and update files.\u000a• Answer the director''s phone in his absence.\u000a• Maintaining daily, weekly and monthly reports.\u000a• Assist in general administration and HR operation related activities.\u000aThanks\u000aT D Surendra'),NULL);
INSERT INTO candidates VALUES(827,9,NULL,'Sravan Kumar Reddy','kunchalasravan@gmail.com','76',NULL,NULL,'Strategic Program and Operations Leader with 12+ years of experience in scaling learner-centric delivery systems and academic operations. Proven expertise in data-driven operational frameworks, cross-functional team management, and implementing AI-driven engagement strategies.','pending','row_11','2025-11-20 11:53:50','2025-11-25 11:00:55','+919963904689',NULL,NULL,unistr('01/2008\u000aMBA:\u000aFinance and Marketing\u000aOsmania University\u000a01/2005\u000aB.Sc:\u000aOsmania University\u000akunchalasravan@gmail.com\u000a(+91) 9963904689\u000aHyderabad India\u000aKey Skills\u000aOperational Leadership•\u000aStakeholder Management•\u000aCross-functional Collaboration•\u000aB2B and B2C Operations•\u000aAcademic Operations•\u000aProcess improvement and SOP\u000aimplementation\u000a•\u000aDelivery Management•\u000aTeam Management•\u000aEducation\u000aCertifications\u000aGoogle Project Management\u000aCertification\u000a•\u000aAccredited Professional Master\u000aNLP Practitioner Diploma\u000a•\u000aStrategic Program and Operations Leader with 12+ years of experience in scaling\u000alearner-centric delivery systems, academic operations, and customer success\u000aacross B2C and B2B education ecosystems. Proven expertise in designing and\u000amanaging end-to-end learner/user journeys—from onboarding and engagement to\u000aacademic success and completion. Skilled in building data-driven operational\u000aframeworks, SOPs, and learner support systems at scale. Strong leadership in\u000across-functional team management, partner coordination, and technology\u000aadoption to drive delightful, seamless learning experiences for learners and users.\u000aTaranirudh Foundation - Head- Programs And Operations\u000aHyderabad\u000a07/2025 - Current\u000aInvest4Edu Pvt Ltd - Sr Operations Manager\u000aHyderabad\u000a12/2024 - 06/2025\u000aLeadership Boluverd Private Limited - Customer Success Manager\u000a12/2022 - 10/2024\u000aSravan Kumar Reddy\u000aProfile Summary\u000aWork Experience\u000aAct as a strategic advisor to leadership, aligning organizational goals with\u000aoperational execution across education and technology-driven initiatives.\u000a•\u000aSpearheaded the launch of two apps (Khanaa and Rainbows of Joy), targeting\u000aover 50,000 users in 12 months through strategic planning, resource allocation,\u000aand performance tracking.\u000a•\u000aDesigned program roadmaps, performance dashboards, and reporting\u000aframeworks for donor/investor engagement.\u000a•\u000aEstablished SOPs for training delivery and cross-team collaboration, enhancing\u000aefficiency by 30%.\u000a•\u000aLed customer success and learner engagement strategy across digital platforms,\u000aimproving retention and satisfaction scores through structured onboarding, and\u000areal-time support.\u000a•\u000aDesigned SOPs and escalation workflows for learner support and academic\u000adelivery, reducing resolution time by 40%.\u000a•\u000aPartnered with product and tech teams to implement AI-driven engagement\u000anudges, and progress tracking dashboards.\u000a•\u000aManaged a cross-functional delivery team, ensuring smooth operations across\u000acohorts, live classes, and learner touchpoints.\u000a•\u000aTranslated learner feedback into structured product and service improvements.•\u000aManage zonal school operations to ensure smooth functioning and compliance\u000awith company standards.\u000a•\u000a\u000aNspira Management Services Pvt.Ltd - Manager - Product Operations\u000a08/2019 - 11/2022\u000aJAY ROBOTIX LEARNING INDIA PVT LTD - Principal Consultant - Operations\u000aHyderabad\u000a04/2015 - 08/2019\u000aKriyative Learning Solutions Private Limited - Sr Executive\u000a01/2012 - 12/2014\u000aBASIX - Executive\u000a12/2009 - 05/2012\u000aFacilitated workshops and onboarding for partner schools, supporting the\u000aadoption of best practices.\u000a•\u000aProduce comprehensive reports on account progress and outcomes for effective\u000acommunication with team members, stakeholders, and for potential use in case\u000astudies or company training.\u000a•\u000aHeaded nLearn product operations (also other digital products like nTeacher,\u000anMonitor, and Lark) across 300+ schools and colleges, ensuring a high-quality\u000alearner/user experience through structured onboarding, scheduling, and\u000aperformance monitoring.\u000a•\u000aImplemented process automation and delivery SOPs, enhancing delivery\u000ahygiene, and operational accuracy.\u000a•\u000aCoordinated with academic, product, and tech teams to build data dashboards\u000afor engagement, retention, and academic outcomes. Also, for new feature\u000adevelopments.\u000a•\u000aManaged product rollouts, institutional training, and feedback loops for\u000acontinuous improvement.\u000a•\u000aSpearheaded a STEM lab implementation project across 25 government schools\u000ain Telangana, in collaboration with the Social Welfare Department (TSWREIS).\u000a•\u000aDesigned and delivered skill development training for AP SC Finance Corporation\u000a(APSCCFC), leading to a measurable increase in learner employability.\u000a•\u000aRecruited and trained over 35 master trainers; monitored delivery, learning\u000aoutcomes, and program adherence.\u000a•\u000aPlanned, organized, and executed sales strategies and territory plans.•\u000aResponsible for developing and maintaining commercially productive\u000arelationships with both new and existing clients.\u000a•\u000aResponsible for the end-to-end life cycle of the customer, from acquisition to\u000aretention.\u000a•\u000aResponsible for teacher training in the use of the curriculum.•\u000aIdentifying important decision-makers, developing key relationships, and\u000anetworking in a professional manner.\u000a•\u000aWrote and implemented standard operating procedures for credit personnel to\u000aensure consistency in unit operations\u000a•\u000aStreamlined processes for early identification of potential credit system and\u000amonitoring problems\u000a•\u000aRecruiting team for operations•\u000aReported key performance indicators to department heads for the management•\u000a\u000ahttps://www.linkedin.com/in/sravan-k-51416439/\u000aof positive cash flow and to adjust credit risk policies and improvements\u000aManaged 2cr Urban credit portfolio•\u000aAppraising, Credit Underwriting and sanctioning/rejecting of the loan proposals•\u000aImplemented high standards of credit underwriting, which resulted in 95% of\u000aapproval rate\u000a•\u000aLanguages\u000aEnglish•\u000aHindi•\u000aTelugu•\u000aSociallink'),NULL);
