INSERT INTO candidates VALUES(829,9,NULL,'Jeevan Santosh Sandaka','iamjeevansantosh@gmail.com','93',NULL,NULL,'Jeevan Santosh Sandaka is a Strategic Business Consultant with extensive experience supporting executive leadership and CEO offices in driving business transformation, growth strategy, and operational excellence. He demonstrates strong analytical acumen, project management capabilities, and a proven track record in retail expansion and international market strategy.','pending','row_13','2025-11-20 11:53:50','2025-11-25 11:00:55','+91 9492233359',NULL,NULL,unistr('Jeevan Santosh Sandaka\u000aBusiness Consultant, EverFlourish Advisors LinkedIn | WA: +91 9492233359 | iamjeevansantosh@gmail.com\u000aBusiness Consultant | Ex-AGM (Franchise Head, Suta) | Retail/Offline Development & Expansion| International Expansion & Sales | Strategy\u000aConsulting | Project Management | B2B Business | Business Process Improvements | Supply Chain Management| Program Management\u000aStrategic Business Consultant with work experience in supporting executive leadership and CEO offices to drive business transformation, growth\u000astrategy, and operational excellence. Skilled in Strategy Consulting, Retail Expansion, Project & Program Management, managing cross functional\u000aactivities, and International Market Strategy, specializing in Retail channel development & International B2B expansion with a proven track record.\u000aSKILLS\u000aConsulting & Project Management Skills:\u000a• Business Process Improvements • Project Management (CCPM) • Supply Chain Optimization • Stakeholder Management\u000a• Sales Process Optimization • Operational Efficiency • Business Transformation • Data Driven decision making\u000a• Strategic Planning & Execution • Cross-functional Team Leadership • Project & Program Oversight • Change Management\u000aBusiness Development Skills:\u000a• Franchising Strategy • Retail Expansion & Investor relations • Financial Modelling skills • P&L Analysis\u000a• Retail Operations Management • Contract Negotiations • GTM & Growth Strategy • Market Research\u000a• Legal Agreements diligence • International B2B Development • End-to-End Project Delivery • Budget & Cost Controlling\u000aTechnical Skills:\u000a• Advanced MS Excel • Power BI & Tableau • MS SQL • Ginesys & ERPNext (ERP)\u000a• Data Analytics • Business Analysis • ROI & Data Analysis • Data Visualization Skills\u000aWORK EXPERIENCE\u000aEverFlourish Advisory Hyderabad, India\u000aBusiness Consultant Mar 2025-Present\u000a Provided strategic advisory for business transformation and execution support to CEOs and leadership teams across multiple industries\u000a Developed a Buffer Penetration Report to improve real-time Inventory replenishment among central and regional warehouses that lead to\u000aclient’s business transformation - minimize stock-outs, reduce both average lead time and average monthly inventory working capital by ~25%\u000a Designed and rolled out KPIs & KRAs for 10 department heads that enabled CEO to track execution against goals with >95% coverage and\u000aimproving review cadence from annually to quarterly & monthly, and reduce performance review prep time by 30%\u000a Designed and implemented a CCPM-based Project Management Tracker for 9+ PM-KUSUM and C&I projects worth of 250+ Crores- streamlining\u000aproject governance, stakeholder alignment, and execution by reducing planning cycle time by 20% & improving on-time completion rate by 10%\u000a Solved unstructured problems by creating reports(9), dashboards(6), and management presentations(20+) to manage client’s daily operations\u000a& streamline business flow covering 6 business functions\u000a Analysed client business challenges across SCM, Sales, HR and Strategy to develop and implement processes that streamlined workflow\u000a Identified gaps & redesigned sales process to address bottlenecks, improving productivity & conversion rate by ~30% within 2 months\u000aSUTA Mumbai, India\u000aAssistant General Manager – Offline Expansion (Franchise Head) Mar 2022-Mar 2025\u000a Responsible for developing Offline Channel for Suta, planned 17 Retail outlets, including 15 Franchise outlets & 2 Company stores\u000a Successfully planned 3 CAPEX light Franchise models to ensure minimum cash-outflow for the bootstrapped brand-Suta\u000a Increased company''s turnover from 2% to 29% from retail channel in three years with key strategic planning and budget management\u000a Successfully managed to convince Investors across India for a cumulative investment of 10+ Cr in retail store plannings\u000a Created International go-to-market entry strategy (B2B Business Development) in Asian, North America and African markets to generate leads\u000aand successfully generate 2+ Crores revenue in 2 years\u000a Supervised Retail operations and analysed P&L s’ to reduce overall Operational expenses by 6% and increase EBITDA margins by ~2.7%\u000a Developed multiple Franchise & Financial models, Cashflow Statements, Project Budgets, P&L Analysis, Legal drafts, store SOPs & Design-BOQs\u000a\u000a Analysed raw data using advanced data analytics to generate reports & insights on Sales & Inventory Forecast and Consumer behaviour, creating\u000aData Visualization- Power BI dashboards\u000a Implemented robust project management frameworks to create comprehensive project tracking tools & methodologies for 12+ projects\u000a Drafted 50+ agreements with legal professionals and successful in hard negotiations with leasing heads, lessors, Investors & Cas\u000aTATA CONSULTANCY SERVICES Hyderabad, India\u000aSystem Engineer – MS SQL Database Admin Dec 2016-Sept 2019\u000a Administered, supported and monitored MS SQL databases, Performed preventive maintenance activities like causal analysis, data problems\u000aresolution & performance tuning along with regular ticket resolutions, user requests handling within defined SLA\u000a Documented & analysed business reports to provide performance improvement feedback and follow-up with Onsite leads\u000a Implemented a new onboarding curriculum that combined hands-on technical training with soft skills workshops, increasing retention rates of\u000afreshers by 25% over a six-month period\u000a Represented Offshore Delivery Centre with a team comprising 10 members in delivering high performance that led to client appreciation and\u000awinning the ‘Star of the Month’ award at TCS\u000aEDUCATION\u000aMBA (International Business) Delhi, India\u000aIndian Institute of Foreign Trade 2020-2022\u000aBTech (Civil Engineering) Visakhapatnam, India\u000aGITAM University 2012-2016\u000aCERTIFICATIONS\u000a Strategic Management & Business Transformation Jan 2025\u000a Financial Analysis & Financial Modelling using MS Excel Aug 2024\u000a PI 300: Microsoft Power BI Data Analyst May 2023\u000a Lean Six Sigma Green Belt (ICGB)- KPMG July 2021\u000aAWARDS\u000a Awarded ''Star Employee of the Year'' award at Suta 2024\u000a Awarded ''Rising Employee of the Year'' award at Suta 2023\u000a Awarded ''Star of the month'' Employee Award in TCS 2019\u000aINTERNSHIP & PROJECT\u000aSUTA Apr 2021-Jun 2021\u000a Worked on ''Corporate Gifting'' project by analysing competitors'' businesses & gifting practices across various industry verticals\u000a Successfully completed deliverables a week prior due date and converted 4 leads and closed additional project- ‘How brands approaching\u000acustomers internationally'' to suggest critical insights and bagged a PPO from Suta\u000aACTIVITIES AND ACHIEVEMENTS\u000a National Finalist in BIM Trichy''s Crescita''21 National Management Fest\u000a Headed IMCC club to prepare salient documents & publications for institutional representation with corporate organizations\u000a Hosted Hyderabad Joint Area Level Contest- 2018 as Contest Chair & Published Toastmasters newsletter across India\u000a Worked as Assistant Vice President Membership, Vice President Public Relations & Treasurer in TCS Hyderabad Toastmasters Club\u000aSOFTWARES\u000a Power BI • Tableau • Microsoft SQL • ERPNext • Ginesys\u000aLANGUAGES\u000a English • Hindi • Telugu • French'),NULL);
INSERT INTO candidates VALUES(830,9,NULL,'Shivam Saxena','ssaxena310@gmail.com','76',NULL,NULL,'Shivam Saxena is an experienced founder with a strong background in launching and scaling D2C and health-tech startups. He demonstrates expertise in product ownership, growth marketing, operational management, and cross-functional team leadership.','pending','row_14','2025-11-20 11:53:50','2025-11-25 11:00:55','+91-7003796493',NULL,NULL,unistr('Shivam Saxena\u000a+91-7003796493 | ssaxena310@gmail.com | Kolkata\u000awww.linkedin.com/in/shivam-saxena-34a26b141\u000aEXPERIENCE\u000aFitodo (Health-focused Meal Delivery Startup) Aug. 2024 — Present\u000aFounder / Product Owner Pune, India\u000a• Built and launched a D2C high-protein meal brand from scratch, achieving ₹1L+ in revenue within the first 3\u000amonths through lean MVP execution and iterative testing.\u000a• Owned product lifecycle end-to-end — from user research, prototyping, and feature planning to delivery\u000aoperations and growth marketing\u000a• Collaborated cross-functionally with chefs, delivery partners, and interns, scaling to a 6-member team and\u000aensuring on-time meal fulfillment with >90% CSAT.\u000a• Executed growth experiments via Meta ads and referral programs, acquiring 100+ users within 60 days at ₹300–\u000a₹350 CAC and improving retention to 70%.\u000a• Conducted stakeholder discovery across gyms and corporates, setting up 12+ fitness stalls and generating B2B\u000ainterest; launched Fitodo on Zomato in March to drive D2C traction.\u000a• Launched a ₹99 trial campaign and used customer feedback to optimize the personalized meal plan system,\u000aresulting in improved user satisfaction and engagement.\u000aMedcrest (Health-Tech Startup) July. 2021 — June.2024\u000aCo-Founder (Product & Growth) Remote, India\u000a• Launched a brand comparison platform integrating 6+ major brands (Apollo24|7, Tata1mg, Netmeds, Truemeds,\u000aPharmEasy, MediBuddy), generating ₹3 Cr in affiliate sales over 3 years.\u000a• Defined product vision and roadmap, collaborating with design & dev teams to launch an MVP on\u000aWordPress, reducing bounce rate by 35%.\u000a• Conducted market research and implemented WhatsApp-based ordering support, reducing drop-offs by 40%\u000aand boosting CSAT to 75%.\u000a• Developed a brand comparison algorithm that enabled users to save up to 30% per order, improving\u000acustomer retention from 35% to 75% within 6 months.\u000a• Led a 20-member cross-functional team (tech, support, ops), driving growth sprints and agile releases using\u000aJira, optimizing product performance with tools like Google Analytics, Ahrefs, and Buffer.\u000aFreshhcart (Grocery Delivery Platform) Feb. 2021 — July.2021\u000aFounder Kolkata, India\u000a• Launched and scaled a 2-hour grocery delivery brand, generating ₹6-7L revenue in 6 months with 150%\u000aROI through targeted Facebook Ads, Google AdSense & GMB campaigns.\u000a• Managed end-to-end operations for a 9-member team, ensuring 90% stock availability through strategic\u000abrand partnerships (Flavarich, Tops, Chings, Veeba).\u000a• Navigated market dynamics and intense competition from 10-min delivery startups, leading to a strategic\u000ashutdown after strong performance despite capital challenges.\u000aIndosta Motors (Start-up focusing on manufacturing of EV sedan) Dec 2019 — Jan 2021\u000aSenior Engineer- R & D Noida, India\u000a• Led design and manufacturing of electric sedan in Catia V3, managing R&D, vendors, and suppliers.\u000aISIE India Aug 2019 — Nov 2019\u000aTechno Management Noida, India\u000a• Streamlined CRM data migration by sanitizing raw inputs and efficiently importing multi-source datasets.\u000aNissan India Nov 2018 — May 2019\u000aSales & Marketing Associate Kolkata, India\u000a• Managed two Nissan & Datsun dealerships, driving ₹3 Cr+ sales while ensuring premium customer experience.\u000aPROJECT\u000a• ISL App & Website UX Strategy – Identified retention gaps; prioritized fixes using MoSCoW & Impact-Effort;\u000aproposed gamification & unified content funnel.\u000a• Formula Bharat & Supra SAE – Built student F1 cars; led manufacturing & design.\u000a• Airbag System Simulation – Designed 6-airbag system in CATIA V3; tested safety with LS-DYNA.\u000aSKILLS\u000aProduct: Product Strategy, Road mapping, User Research, A/B Testing, GTM\u000aTools: Jira, Figma, Notion, Google Analytics, Ahrefs, Buffer\u000aSoft Skills: Leadership, Stakeholder Management, Agile, Communication\u000aEDUCATION\u000aMCKV Institute of Engineering\u000aBachelor of Technology in Automobile Engineering (7.21/10) DGPA\u000aAug. 2015 — May 2019\u000aKolkata, India'),NULL);
