INSERT INTO candidates VALUES(845,9,NULL,'Shubham Pramod Salunke','shubhampsalunke@gmail.com','59',NULL,NULL,'Analytical and results-driven professional with experience in operations, digital marketing, and technical support, demonstrating strong communication and leadership skills.','pending','row_29','2025-11-20 11:53:50','2025-11-25 11:00:55','8669130838',NULL,NULL,unistr('Shubham Pramod Salunke\u000aEmail: shubhampsalunke@gmail.com\u000aPh: 8669130838\u000aAnalytical, results-driven graduate eager to utilize skills and knowledge gained through education and experience to assist organizations\u000ain developing and executing strategies to drive business growth. Good communication skills and strong ability to lead teams through\u000ademanding situations.\u000aExperience –\u000aAmazon: Quality Specialist (Operation Technology Support)\u000aTroubleshooting, diagnosing and fixing static route issues, developing monitoring solutions, updating, tracking and resolving technical challenges.\u000aResponsibilities also include working alongside development on Amazon Corporate and Divisional Software projects, enhancing our current tools, automation of\u000asupport processes and documentation of our systems.\u000aIGM Diet: Marketing Manager (2021-22)\u000aManagement of Digital Marketing, Social Media Campaigns, and Web Development for the IGMdiet.com.\u000aBewa Bottles: Operation Manager (2020-21)\u000aManagement of daily E-commerce operation, vendor management, product sourcing for Bewa Copper water bottles.\u000aACADEMIC QUALIFICATIONS\u000aB. E MECHANICAL Government College of Engineering and Research (Avasari) Pune, Savitribai Phule\u000aPune University (Pune University)\u000a68.73% Distinction 2019\u000aCLASS XII SCIENCE Residential Junior College Ahmednagar, Maharashtra State Board of Secondary\u000aand Higher Secondary Education\u000a87.38% Distinction 2015\u000aCLASS X Shri Chhatrapati Shivaji High School Deolali Pravara, Maharashtra State Board of\u000aSecondary and Higher Secondary Education\u000a94.55% Distinction 2013\u000aCOURSES AND CERTIFICATIONS\u000aGoogle Analytics for Beginners Google Analytics Academy Till 12\u000ath \u000aSeptember\u000a2023\u000aFacebook Marketing Course Coursera & Facebook -\u000aACADEMIC PROJECTS & PAPERS\u000aProject \u000aSemi-Automatic Cooking Machine 2018-2019\u000a Designed and Fabricated a cooking machine having continuous rotational motion, which is used to mix ingredients.\u000a Assembled Temperature controller, Digital timer Switch for automation to reduces human involvement and monitoring.\u000a Applicable for roasting, slow cooking, shallow frying, and cooking one-pot recipes.\u000aPaper \u000aAnimatronics 2017-2018\u000a Studied Animatronics technology, its uses, applications and future scope.\u000a Prepared a Seminar report and presentation about the concept, materials, design, and applications of the Animatronics.\u000aWorkshop \u000aWorkshop on Two-Wheeler Engine 2016-2017\u000a Completed a Five Days workshop, learned about assembly and dismantling of Four Stroke Single Cylinder Engine.\u000aKnowledgeable about : Facebook(Meta) ads, Google ads, Google Analytics, No code Web development, Social Media\u000aManagement, MS Office, Drop Shipping, etc.\u000a'),NULL);
INSERT INTO candidates VALUES(846,9,NULL,'SATISH KUMAR SUDHALA','sudhalasatish@gmail.com','30',NULL,NULL,'Satish Kumar Sudhala has 2.9 years of experience in IT Infrastructure and 1.2 years as a Staff Writer, demonstrating skills in stakeholder management, communication, and analytical problem-solving through a smartphone-based accident detection project.','pending','row_30','2025-11-20 11:53:50','2025-11-25 11:00:55','+91-9642349593',NULL,NULL,unistr('SATISH KUMAR SUDHALA\u000asudhalasatish@gmail.com\u000a+91-9642349593\u000aCareer Objective\u000aTo get into an organization where I can apply my knowledge and innovative skills\u000abeing a part of a challenging team required for the growth of the organization\u000athereby increasing my technical skills.\u000aExperience\u000a◾ Served as a Associate, IT Infrastructure at GlobalLogic Technologies\u000aPvt Limited.\u000a•Period : December 2021 to September 2024(2.9 Years)\u000aRoles and Responsibilities :\u000a1.Jira Ticketing Tool- Service Desk Tickets resolving within SLAs and tech\u000asupport for all the end users on a daily basis.\u000a2.Allocation and deallocation of all assets regularly.\u000a3.Email, Chat and Mobile Support to the users.\u000a4.OS Configuration on a daily basis.\u000a5.Updating the Flexera software on a daily basis to track easily and effectively\u000awith all the units. Maintaining all hardware assets of the organization.\u000a6. Vendor, Stakeholder Management internally and externally.\u000a◾ Served as a Staff Writer at GlobalData Plc for fourteen months.\u000a•Period : September 2020 to November 2021(1.2 Years)\u000aAt GlobalData, served in maintaining the data and articles respective to different\u000acompanies.\u000aAcademics\u000a◾ \u000aBachelor of Technology in Computer Science from Aurora’s\u000aEngineering College, Hyderabad, Telangana State.\u000a• Year 2015 – 2019. • Aggregate of 60.40 %.\u000a◾ Intermediate Education (10 +2) ) in MPC Stream from Telangana State\u000aBoard of Intermediate Education, Hyderabad, Telangana State.\u000a\u000a• Year 2013-2015. • Aggregate of 88.1%.\u000a◾ Secondary School Education from Board of Secondary Education: Andhra\u000aPradesh, Hyderabad.\u000a• Year 2012-2013. • GPA 9.3.\u000aMAJOR PROJECT\u000aCAR ACCIDENT DETECTION AND NOTIFICATION USING\u000aSMARTPHONE\u000aDescription:\u000aAn effective approach for reducing traffic fatalities is: first building an automatic\u000atraffic accident detection system, second, reducing the time between when an\u000aaccident occurs and when first emergency responders are dispatched to the scene of\u000athe accident. On the other hand, the ability to detect traffic accidents using\u000asmartphones has only recently become possible because of the advances in the\u000aprocessing power and sensors deployed on smartphones. Most of the smartphone\u000abased accident detection systems rely on the high speed of the vehicle and the\u000aG-Force value to detect an accident. The notification phase, and immediately after an\u000aaccident is indicated, is used to send detailed information such as images, video,\u000aaccident location, etc. to the emergency responder for fast recovery.\u000aExtra-Curricular Activities\u000a• Participated in the innovation round at IIT Kharagpur.\u000a• Participated and stood 2nd in the state level technical fest of paper\u000apresentation. • Team leader to marketing interns for 2 months at\u000a“BRAINWEAVE”. • Attended workshop on Ethical hacking at MGIT\u000aduring October 2018. • Attended workshop on web development during\u000a11th and 12th of August 2017.\u000aPersonal Profile\u000a• Date of Birth : October 7th , 1997.\u000a• Languages : English, Hindi, Telugu.\u000a• Address :HNO : 40, Venus Rock Heights, Devendar Nagar,\u000aGajularamaram, Hyderabad, Telangana-500055.\u000aSUDHALA SATISH KUMAR'),NULL);
