PRAGMA foreign_keys=OFF;
BEGIN TRANSACTION;
CREATE TABLE users (
  id INTEGER PRIMARY KEY AUTOINCREMENT,
  email TEXT UNIQUE NOT NULL,
  password_hash TEXT NOT NULL,
  role TEXT CHECK(role IN ('admin','client')) NOT NULL,
  name TEXT,
  status TEXT DEFAULT 'active',
  created_at DATETIME DEFAULT CURRENT_TIMESTAMP,
  updated_at DATETIME DEFAULT CURRENT_TIMESTAMP
, google_sheet_url TEXT, temp_password INTEGER DEFAULT 0, must_change_password INTEGER DEFAULT 0, google_sheets_url TEXT, client_type TEXT DEFAULT 'hr' CHECK(client_type IN ('hr','insurance')), max_sessions INTEGER DEFAULT 5, can_change_password INTEGER DEFAULT 1, admin_password TEXT);
CREATE TABLE wallets (
  id INTEGER PRIMARY KEY AUTOINCREMENT,
  user_id INTEGER UNIQUE NOT NULL,
  balance_cents INTEGER NOT NULL DEFAULT 0,
  updated_at DATETIME DEFAULT CURRENT_TIMESTAMP,
  FOREIGN KEY(user_id) REFERENCES users(id) ON DELETE CASCADE
);
CREATE TABLE transactions (
  id INTEGER PRIMARY KEY AUTOINCREMENT,
  user_id INTEGER NOT NULL,
  type TEXT CHECK(type IN ('recharge','debit')) NOT NULL,
  amount_cents INTEGER NOT NULL,
  description TEXT,
  stripe_payment_id TEXT,
  created_at DATETIME DEFAULT CURRENT_TIMESTAMP,
  FOREIGN KEY(user_id) REFERENCES users(id)
);
CREATE TABLE tool_pricing (
  id INTEGER PRIMARY KEY AUTOINCREMENT,
  tool_name TEXT UNIQUE NOT NULL,
  price_per_unit_cents INTEGER NOT NULL,
  unit_type TEXT NOT NULL,
  description TEXT,
  is_active INTEGER DEFAULT 1,
  updated_at DATETIME DEFAULT CURRENT_TIMESTAMP
);
CREATE TABLE tool_usage (
  id INTEGER PRIMARY KEY AUTOINCREMENT,
  user_id INTEGER NOT NULL,
  tool_name TEXT NOT NULL,
  units_consumed REAL NOT NULL,
  credits_used_cents INTEGER NOT NULL,
  metadata TEXT,
  created_at DATETIME DEFAULT CURRENT_TIMESTAMP,
  FOREIGN KEY(user_id) REFERENCES users(id)
);
CREATE TABLE jobs (
  id INTEGER PRIMARY KEY AUTOINCREMENT,
  user_id INTEGER NOT NULL,
  title TEXT NOT NULL,
  description TEXT,
  requirements TEXT,
  status TEXT DEFAULT 'open',
  created_at DATETIME DEFAULT CURRENT_TIMESTAMP,
  updated_at DATETIME DEFAULT CURRENT_TIMESTAMP, department TEXT,
  FOREIGN KEY(user_id) REFERENCES users(id)
);
CREATE TABLE candidates (
  id INTEGER PRIMARY KEY AUTOINCREMENT,
  user_id INTEGER NOT NULL,
  job_id INTEGER,
  name TEXT,
  email TEXT,
  match_score TEXT,
  matching_skills TEXT,
  missing_skills TEXT,
  summary TEXT,
  status TEXT DEFAULT 'pending',
  sheet_row_id TEXT UNIQUE,
  created_at DATETIME DEFAULT CURRENT_TIMESTAMP,
  updated_at DATETIME DEFAULT CURRENT_TIMESTAMP, mobile TEXT, interview_date TEXT, job_description TEXT, resume_text TEXT, transcript TEXT,
  FOREIGN KEY(user_id) REFERENCES users(id),
  FOREIGN KEY(job_id) REFERENCES jobs(id) ON DELETE SET NULL
);
CREATE TABLE client_analytics_cache (
  id INTEGER PRIMARY KEY AUTOINCREMENT,
  user_id INTEGER UNIQUE NOT NULL,
  total_resumes INTEGER DEFAULT 0,
  interviews_scheduled INTEGER DEFAULT 0,
  interviews_today INTEGER DEFAULT 0,
  weekly_resumes INTEGER DEFAULT 0,
  weekly_interviews INTEGER DEFAULT 0,
  last_updated DATETIME DEFAULT CURRENT_TIMESTAMP,
  FOREIGN KEY(user_id) REFERENCES users(id) ON DELETE CASCADE
);
CREATE TABLE notifications (
  id INTEGER PRIMARY KEY AUTOINCREMENT,
  user_id INTEGER NOT NULL,
  type TEXT NOT NULL, -- 'CREDIT_ADDED', 'LOW_BALANCE', etc.
  message TEXT NOT NULL,
  data TEXT, -- JSON data
  is_read INTEGER DEFAULT 0,
  created_at DATETIME DEFAULT CURRENT_TIMESTAMP,
  FOREIGN KEY (user_id) REFERENCES users(id) ON DELETE CASCADE
);
CREATE TABLE voice_interviews (
  id INTEGER PRIMARY KEY AUTOINCREMENT,
  candidate_id INTEGER NOT NULL,
  job_id INTEGER NOT NULL,
  user_id INTEGER NOT NULL,
  call_id TEXT UNIQUE, -- External platform call identifier
  phone_number TEXT NOT NULL,
  status TEXT DEFAULT 'pending' CHECK (status IN ('pending', 'in_progress', 'completed', 'failed', 'cancelled')),
  start_time DATETIME,
  end_time DATETIME,
  duration_seconds INTEGER DEFAULT 0,
  cost_cents INTEGER DEFAULT 0,
  transcript TEXT,
  ai_analysis TEXT, -- JSON string with analysis results
  overall_score INTEGER DEFAULT 0 CHECK (overall_score >= 0 AND overall_score <= 100),
  recommendation TEXT CHECK (recommendation IN ('hire', 'reject', 'shortlist', 'pending')),
  created_at DATETIME DEFAULT CURRENT_TIMESTAMP,
  updated_at DATETIME DEFAULT CURRENT_TIMESTAMP,
  FOREIGN KEY (candidate_id) REFERENCES candidates(id) ON DELETE CASCADE,
  FOREIGN KEY (job_id) REFERENCES jobs(id) ON DELETE CASCADE,
  FOREIGN KEY (user_id) REFERENCES users(id) ON DELETE CASCADE
);
CREATE TABLE interview_scores (
  id INTEGER PRIMARY KEY AUTOINCREMENT,
  interview_id INTEGER NOT NULL,
  category TEXT NOT NULL, -- technical, communication, cultural_fit, etc.
  score INTEGER NOT NULL CHECK (score >= 0),
  max_score INTEGER NOT NULL CHECK (max_score > 0),
  comments TEXT,
  confidence_level REAL DEFAULT 0.0 CHECK (confidence_level >= 0.0 AND confidence_level <= 1.0),
  created_at DATETIME DEFAULT CURRENT_TIMESTAMP,
  FOREIGN KEY (interview_id) REFERENCES voice_interviews(id) ON DELETE CASCADE
);
CREATE TABLE call_events (
  id INTEGER PRIMARY KEY AUTOINCREMENT,
  interview_id INTEGER NOT NULL,
  event_type TEXT NOT NULL, -- call_started, call_ended, transcript_ready, etc.
  timestamp DATETIME DEFAULT CURRENT_TIMESTAMP,
  event_data TEXT, -- JSON string with event details
  status TEXT DEFAULT 'processed',
  FOREIGN KEY (interview_id) REFERENCES voice_interviews(id) ON DELETE CASCADE
);
CREATE TABLE email_logs (
  id INTEGER PRIMARY KEY AUTOINCREMENT,
  user_id INTEGER, -- ✅ made nullable
  candidate_id INTEGER,
  candidate_email TEXT,
  email_type TEXT CHECK(email_type IN ('selection','rejection','custom')) NOT NULL,
  subject TEXT,
  body TEXT,
  sent_at DATETIME DEFAULT CURRENT_TIMESTAMP,
  candidate_name TEXT,
  meet_link TEXT,
  job_title TEXT,
  status TEXT DEFAULT "sent",
  recipient_email TEXT,
  template_type TEXT,
  job_id INTEGER,
  error_message TEXT,
  gmail_message_id TEXT,
  FOREIGN KEY(user_id) REFERENCES users(id),
  FOREIGN KEY(candidate_id) REFERENCES candidates(id) ON DELETE SET NULL
);
CREATE TABLE policy_types (
  id INTEGER PRIMARY KEY AUTOINCREMENT,
  name TEXT NOT NULL UNIQUE,
  description TEXT,
  is_active BOOLEAN DEFAULT 1,
  created_at DATETIME DEFAULT CURRENT_TIMESTAMP
);
CREATE TABLE motor_policies (
  id INTEGER PRIMARY KEY AUTOINCREMENT,
  user_id INTEGER NOT NULL,
  customer_id INTEGER NOT NULL,
  policy_number TEXT UNIQUE NOT NULL,
  policy_type_id INTEGER NOT NULL,
  company_name TEXT NOT NULL, -- TATA, ICICI, etc.
  vehicle_registration TEXT NOT NULL,
  vehicle_make TEXT,
  vehicle_model TEXT,
  vehicle_year INTEGER,
  policy_start_date DATE NOT NULL,
  policy_end_date DATE NOT NULL,
  premium_amount DECIMAL(10,2) NOT NULL,
  coverage_amount DECIMAL(12,2),
  policy_document_url TEXT, -- PDF link from sheet
  status TEXT DEFAULT 'active' CHECK(status IN ('active','expired','cancelled','renewed')),
  renewal_history TEXT, -- JSON array of renewal dates
  notes TEXT,
  created_at DATETIME DEFAULT CURRENT_TIMESTAMP,
  updated_at DATETIME DEFAULT CURRENT_TIMESTAMP,
  FOREIGN KEY(user_id) REFERENCES users(id) ON DELETE CASCADE,
  FOREIGN KEY(customer_id) REFERENCES insurance_customers(id) ON DELETE CASCADE,
  FOREIGN KEY(policy_type_id) REFERENCES policy_types(id)
);
CREATE TABLE policy_comparisons (
  id INTEGER PRIMARY KEY AUTOINCREMENT,
  user_id INTEGER NOT NULL,
  vehicle_type TEXT NOT NULL,
  company_name TEXT NOT NULL,
  plan_name TEXT NOT NULL,
  premium_range_min DECIMAL(10,2),
  premium_range_max DECIMAL(10,2),
  coverage_amount DECIMAL(12,2),
  key_features TEXT, -- JSON array
  is_active BOOLEAN DEFAULT 1,
  created_at DATETIME DEFAULT CURRENT_TIMESTAMP,
  FOREIGN KEY(user_id) REFERENCES users(id) ON DELETE CASCADE
);
CREATE TABLE renewal_reminders (
  id INTEGER PRIMARY KEY AUTOINCREMENT,
  customer_id INTEGER NOT NULL,
  reminder_type TEXT NOT NULL, -- '30_days', '7_days', '1_day', '7_days_overdue'
  sent_via TEXT NOT NULL, -- 'email', 'whatsapp', 'sms'
  sent_at DATETIME DEFAULT CURRENT_TIMESTAMP,
  FOREIGN KEY (customer_id) REFERENCES insurance_customers(id) ON DELETE CASCADE
);
CREATE TABLE customer_notes (
  id INTEGER PRIMARY KEY AUTOINCREMENT,
  customer_id INTEGER NOT NULL,
  note TEXT NOT NULL,
  created_by INTEGER,
  created_at DATETIME DEFAULT CURRENT_TIMESTAMP,
  FOREIGN KEY (customer_id) REFERENCES insurance_customers(id) ON DELETE CASCADE,
  FOREIGN KEY (created_by) REFERENCES users(id)
);
CREATE TABLE insurance_claims (
  id INTEGER PRIMARY KEY AUTOINCREMENT,
  user_id INTEGER NOT NULL,
  customer_id INTEGER NOT NULL,
  policy_number TEXT,
  insurance_company TEXT,
  vehicle_number TEXT,
  claim_type TEXT CHECK(claim_type IN ('own_damage','third_party','theft','total_loss')),
  incident_date DATE,
  description TEXT,
  claim_status TEXT DEFAULT 'filed' CHECK(claim_status IN ('filed','survey_done','in_progress','approved','rejected','settled')),
  claim_amount DECIMAL(10,2),
  created_at DATETIME DEFAULT CURRENT_TIMESTAMP,
  updated_at DATETIME DEFAULT CURRENT_TIMESTAMP,
  FOREIGN KEY(user_id) REFERENCES users(id) ON DELETE CASCADE,
  FOREIGN KEY(customer_id) REFERENCES insurance_customers(id) ON DELETE CASCADE
);
CREATE TABLE claim_documents (
  id INTEGER PRIMARY KEY AUTOINCREMENT,
  claim_id INTEGER NOT NULL,
  document_type TEXT,
  file_name TEXT,
  file_path TEXT,
  uploaded_at DATETIME DEFAULT CURRENT_TIMESTAMP,
  FOREIGN KEY(claim_id) REFERENCES insurance_claims(id) ON DELETE CASCADE
);
CREATE TABLE claim_status_history (
  id INTEGER PRIMARY KEY AUTOINCREMENT,
  claim_id INTEGER NOT NULL,
  old_status TEXT,
  new_status TEXT,
  notes TEXT,
  changed_at DATETIME DEFAULT CURRENT_TIMESTAMP,
  FOREIGN KEY(claim_id) REFERENCES insurance_claims(id) ON DELETE CASCADE
);
CREATE TABLE message_logs (
  id INTEGER PRIMARY KEY AUTOINCREMENT,
  customer_id INTEGER,
  message_type TEXT DEFAULT 'general',
  channel TEXT NOT NULL,
  message_content TEXT,
  status TEXT DEFAULT 'sent',
  sent_at DATETIME DEFAULT CURRENT_TIMESTAMP, customer_name_fallback TEXT, client_key TEXT,
  FOREIGN KEY (customer_id) REFERENCES insurance_customers(id) ON DELETE SET NULL
);
CREATE TABLE insurance_policies (
        id INTEGER PRIMARY KEY AUTOINCREMENT,
        user_id INTEGER NOT NULL,
        policy_number TEXT UNIQUE,
        policy_type TEXT,
        customer_name TEXT,
        customer_email TEXT,
        customer_phone TEXT,
        premium_amount REAL,
        status TEXT DEFAULT 'active',
        start_date TEXT,
        end_date TEXT,
        created_at DATETIME DEFAULT CURRENT_TIMESTAMP,
        updated_at DATETIME DEFAULT CURRENT_TIMESTAMP,
        FOREIGN KEY (user_id) REFERENCES users(id) ON DELETE CASCADE
      );
CREATE TABLE insurance_customers (id INTEGER PRIMARY KEY AUTOINCREMENT, user_id INTEGER NOT NULL, name TEXT NOT NULL, mobile_number TEXT NOT NULL, renewal_date TEXT, premium_mode TEXT, premium REAL DEFAULT 0, vertical TEXT DEFAULT 'motor', product TEXT, registration_no TEXT, current_policy_no TEXT, company TEXT, status TEXT DEFAULT 'pending', new_policy_no TEXT, new_company TEXT, policy_doc_link TEXT, thank_you_sent TEXT, reason TEXT, email TEXT, created_at DATETIME DEFAULT CURRENT_TIMESTAMP, updated_at DATETIME DEFAULT CURRENT_TIMESTAMP, insurance_activated_date TEXT, od_expiry_date TEXT, tp_expiry_date TEXT, notes TEXT DEFAULT '', last_year_premium REAL, cheque_hold TEXT, payment_date TEXT, cheque_no TEXT, cheque_bounce TEXT, owner_alert_sent TEXT, veh_type TEXT, modified_expiry_date TEXT, FOREIGN KEY (user_id) REFERENCES users(id) ON DELETE CASCADE);
CREATE TABLE user_ip_allowlist (
          id INTEGER PRIMARY KEY AUTOINCREMENT,
          user_id INTEGER NOT NULL,
          ip_address TEXT NOT NULL,
          created_at DATETIME DEFAULT CURRENT_TIMESTAMP,
          FOREIGN KEY (user_id) REFERENCES users(id) ON DELETE CASCADE
        );
CREATE TABLE sessions (
          id TEXT PRIMARY KEY,
          user_id INTEGER NOT NULL,
          token TEXT NOT NULL,
          ip_address TEXT,
          created_at DATETIME DEFAULT CURRENT_TIMESTAMP,
          FOREIGN KEY (user_id) REFERENCES users(id) ON DELETE CASCADE
        );
CREATE TABLE kmg_message_logs (
          id INTEGER PRIMARY KEY AUTOINCREMENT,
          customer_id INTEGER,
          customer_name TEXT,
          customer_mobile TEXT,
          message_type TEXT,
          channel TEXT DEFAULT 'whatsapp',
          message_content TEXT,
          status TEXT DEFAULT 'sent',
          sent_at DATETIME DEFAULT CURRENT_TIMESTAMP,
          FOREIGN KEY (customer_id) REFERENCES insurance_customers(id) ON DELETE SET NULL
        );
CREATE TABLE joban_message_logs (
          id INTEGER PRIMARY KEY AUTOINCREMENT,
          customer_id INTEGER,
          customer_name TEXT,
          customer_mobile TEXT,
          message_type TEXT,
          channel TEXT DEFAULT 'whatsapp',
          message_content TEXT,
          status TEXT DEFAULT 'sent',
          sent_at DATETIME DEFAULT CURRENT_TIMESTAMP,
          FOREIGN KEY (customer_id) REFERENCES insurance_customers(id) ON DELETE SET NULL
        );
CREATE TABLE user_profiles (
          id INTEGER PRIMARY KEY AUTOINCREMENT,
          user_id INTEGER NOT NULL,
          profile_name TEXT NOT NULL,
          avatar_color TEXT DEFAULT '#6366f1',
          is_default INTEGER DEFAULT 0,
          created_at DATETIME DEFAULT CURRENT_TIMESTAMP,
          last_used_at DATETIME DEFAULT CURRENT_TIMESTAMP,
          FOREIGN KEY (user_id) REFERENCES users(id) ON DELETE CASCADE
        );
CREATE TABLE activity_logs (
            id INTEGER PRIMARY KEY AUTOINCREMENT,
            user_id INTEGER NOT NULL,
            profile_id INTEGER,
            activity_type TEXT NOT NULL,
            activity_description TEXT,
            metadata TEXT,
            created_at DATETIME DEFAULT CURRENT_TIMESTAMP,
            FOREIGN KEY (user_id) REFERENCES users(id) ON DELETE CASCADE,
            FOREIGN KEY (profile_id) REFERENCES user_profiles(id) ON DELETE SET NULL
          );
CREATE TABLE client_profiles (
          id INTEGER PRIMARY KEY AUTOINCREMENT,
          user_id INTEGER NOT NULL,
          profile_name TEXT NOT NULL,
          profile_password TEXT NOT NULL,
          role TEXT NOT NULL DEFAULT 'user',
          created_at DATETIME DEFAULT CURRENT_TIMESTAMP,
          updated_at DATETIME DEFAULT CURRENT_TIMESTAMP,
          FOREIGN KEY (user_id) REFERENCES users(id) ON DELETE CASCADE,
          UNIQUE(user_id, profile_name)
        );
CREATE TRIGGER update_voice_interviews_timestamp 
  AFTER UPDATE ON voice_interviews
  BEGIN
    UPDATE voice_interviews SET updated_at = CURRENT_TIMESTAMP WHERE id = NEW.id;
  END;
CREATE INDEX idx_candidates_user_id ON candidates(user_id);
CREATE INDEX idx_candidates_job_id ON candidates(job_id);
CREATE INDEX idx_candidates_status ON candidates(status);
CREATE INDEX idx_candidates_email ON candidates(email);
CREATE INDEX idx_transactions_user_id ON transactions(user_id);
CREATE INDEX idx_transactions_created_at ON transactions(created_at);
CREATE INDEX idx_tool_usage_user_id ON tool_usage(user_id);
CREATE INDEX idx_tool_usage_created_at ON tool_usage(created_at);
CREATE INDEX idx_jobs_user_id ON jobs(user_id);
CREATE INDEX idx_analytics_cache_user_id ON client_analytics_cache(user_id);
CREATE INDEX idx_analytics_cache_updated ON client_analytics_cache(last_updated);
CREATE INDEX idx_notifications_user_unread ON notifications(user_id, is_read);
CREATE INDEX idx_voice_interviews_candidate ON voice_interviews(candidate_id);
CREATE INDEX idx_voice_interviews_job ON voice_interviews(job_id);
CREATE INDEX idx_voice_interviews_user ON voice_interviews(user_id);
CREATE INDEX idx_voice_interviews_status ON voice_interviews(status);
CREATE INDEX idx_voice_interviews_call_id ON voice_interviews(call_id);
CREATE INDEX idx_interview_scores_interview ON interview_scores(interview_id);
CREATE INDEX idx_call_events_interview ON call_events(interview_id);
CREATE INDEX idx_call_events_type ON call_events(event_type);
CREATE INDEX idx_email_logs_user_id ON email_logs(user_id);
CREATE INDEX idx_motor_policies_user_id ON motor_policies(user_id);
CREATE INDEX idx_motor_policies_customer_id ON motor_policies(customer_id);
CREATE INDEX idx_motor_policies_company ON motor_policies(company_name);
CREATE INDEX idx_motor_policies_status ON motor_policies(status);
CREATE INDEX idx_motor_policies_end_date ON motor_policies(policy_end_date);
CREATE INDEX idx_renewal_reminders_customer ON renewal_reminders(customer_id);
CREATE INDEX idx_customer_notes_customer ON customer_notes(customer_id);
CREATE INDEX idx_claims_user_id ON insurance_claims(user_id);
CREATE INDEX idx_claims_customer_id ON insurance_claims(customer_id);
CREATE INDEX idx_claims_status ON insurance_claims(claim_status);
CREATE INDEX idx_claim_documents_claim_id ON claim_documents(claim_id);
CREATE INDEX idx_claim_status_history_claim_id ON claim_status_history(claim_id);
CREATE INDEX idx_message_logs_customer ON message_logs(customer_id);
CREATE INDEX idx_message_logs_sent_at ON message_logs(sent_at);
COMMIT;
